head.script:
//
(function(){
  try {
    var t = localStorage.getItem('rankrseo-theme');
    if (t === 'dark') {
      document.documentElement.setAttribute('data-theme', 'dark');
    } else if (!t && window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      document.documentElement.setAttribute('data-theme', 'dark');
    }
  } catch(e) {}
})();
//

b:if.b:skin:
/* --- CSS Variables --- */
:root {
  --primary: #2563EB; --primary-dark: #1D4ED8; --primary-light: #60A5FA; --primary-rgb: 37,99,235;
  --secondary: #0F172A; --secondary-light: #1E293B; --accent: #14B8A6; --accent-dark: #0D9488;
  --accent-light: #5EEAD4; --accent-rgb: 20,184,166;
  --bg: #FFFFFF; --bg-alt: #F8FAFC; --bg-card: #FFFFFF;
  --text: #0F172A; --text-light: #64748B; --text-lighter: #94A3B8;
  --border: #E2E8F0; --border-light: #F1F5F9;
  --shadow-sm: 0 1px 3px rgba(0,0,0,0.06), 0 1px 2px rgba(0,0,0,0.04);
  --shadow: 0 4px 6px -1px rgba(0,0,0,0.06), 0 2px 4px -2px rgba(0,0,0,0.04);
  --shadow-md: 0 10px 15px -3px rgba(0,0,0,0.08), 0 4px 6px -4px rgba(0,0,0,0.04);
  --shadow-lg: 0 20px 25px -5px rgba(0,0,0,0.1), 0 8px 10px -6px rgba(0,0,0,0.04);
  --shadow-xl: 0 25px 50px -12px rgba(0,0,0,0.15);
  --radius-sm: 6px; --radius: 8px; --radius-md: 12px; --radius-lg: 16px; --radius-xl: 20px; --radius-full: 9999px;
  --font-body: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --font-heading: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --transition: 0.3s cubic-bezier(0.4,0,0.2,1); --transition-fast: 0.15s cubic-bezier(0.4,0,0.2,1);
  --header-h: 72px; --header-h-scroll: 60px; --container: 1200px; --container-narrow: 800px;
  --gap: 24px; --gap-sm: 16px; --gap-lg: 32px;
}
[data-theme="dark"] {
  --bg: #0B1121; --bg-alt: #111827; --bg-card: #1E293B;
  --text: #F1F5F9; --text-light: #94A3B8; --text-lighter: #64748B;
  --border: #334155; --border-light: #1E293B;
  --shadow-sm: 0 1px 3px rgba(0,0,0,0.4); --shadow: 0 4px 6px -1px rgba(0,0,0,0.4);
  --shadow-md: 0 10px 15px -3px rgba(0,0,0,0.5); --shadow-lg: 0 20px 25px -5px rgba(0,0,0,0.5);
  --shadow-xl: 0 25px 50px -12px rgba(0,0,0,0.6);
}

/* --- Reset --- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; -webkit-text-size-adjust: 100%; }
body { font-family: var(--font-body); font-size: 16px; line-height: 1.7; color: var(--text); background: var(--bg); transition: background var(--transition), color var(--transition); overflow-x: hidden; -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }
img, svg, video { max-width: 100%; height: auto; display: block; }
a { color: var(--primary); text-decoration: none; transition: color var(--transition-fast); }
a:hover { color: var(--primary-dark); }
a:focus-visible, button:focus-visible, input:focus-visible, textarea:focus-visible { outline: 2px solid var(--primary); outline-offset: 2px; }
ul, ol { list-style: none; }
h1, h2, h3, h4, h5, h6 { font-family: var(--font-heading); font-weight: 700; line-height: 1.3; color: var(--text); }
h1 { font-size: clamp(2rem, 4vw, 3rem); letter-spacing: -0.02em; }
h2 { font-size: clamp(1.5rem, 3vw, 2.25rem); letter-spacing: -0.01em; }
h3 { font-size: clamp(1.2rem, 2.5vw, 1.65rem); }
h4 { font-size: 1.2rem; }
h5 { font-size: 1.05rem; }
h6 { font-size: 1rem; }
p { margin-bottom: 1em; }
p:last-child { margin-bottom: 0; }
button { cursor: pointer; border: none; background: none; font-family: inherit; font-size: inherit; }
input, textarea, select { font-family: inherit; font-size: inherit; }
::selection { background: var(--primary); color: #fff; }

/* --- Accessibility --- */
.skip-link { position: fixed; top: -100%; left: 50%; transform: translateX(-50%); background: var(--primary); color: #fff; padding: 12px 24px; border-radius: var(--radius); z-index: 99999; font-weight: 600; font-size: 14px; transition: top var(--transition); }
.skip-link:focus { top: 16px; }
.sr-only { position: absolute; width: 1px; height: 1px; padding: 0; margin: -1px; overflow: hidden; clip: rect(0,0,0,0); white-space: nowrap; border-width: 0; }

/* --- Container --- */
.container { width: 100%; max-width: var(--container); margin: 0 auto; padding: 0 20px; }

/* --- Grid --- */
.grid { display: grid; gap: var(--gap); }
.grid-2 { grid-template-columns: repeat(2, 1fr); }
.grid-3 { grid-template-columns: repeat(3, 1fr); }
.grid-4 { grid-template-columns: repeat(4, 1fr); }
.grid-auto { grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); }

/* --- Section Spacing --- */
.section { padding: 48px 0; }
.section:first-child { padding-top: 0; }
.section + .section { padding-top: 0; }
.section-alt { background: var(--bg-alt); }
.section-title { text-align: center; margin-bottom: 24px; }
.section-title h2 { font-size: clamp(1.5rem, 3vw, 2.25rem); margin-bottom: 10px; }
.section-title p { color: var(--text-light); font-size: 0.95rem; max-width: 600px; margin: 0 auto; line-height: 1.6; }
.section-title .highlight { color: var(--primary); }
.section-title .accent-line { width: 48px; height: 3px; background: linear-gradient(90deg, var(--primary), var(--accent)); border-radius: 2px; margin: 10px auto 0; }
.section-subtitle { color: var(--text-light); font-size: 0.95rem; line-height: 1.6; }
.section-cta { text-align: center; margin-top: 24px; }

/* --- SVG Decorative Backgrounds --- */
.hero-svg-bg { position: absolute; inset: 0; overflow: hidden; pointer-events: none; z-index: 0; }
.hero-svg-bg svg { position: absolute; width: 100%; height: 100%; }
.hero-svg-bg .grid-pattern { opacity: 0.04; }
.hero-svg-bg .gradient-orb { position: absolute; border-radius: 50%; filter: blur(80px); opacity: 0.15; }
.hero-svg-bg .orb-1 { width: 600px; height: 600px; background: var(--primary); top: -200px; right: -200px; }
.hero-svg-bg .orb-2 { width: 400px; height: 400px; background: var(--accent); bottom: -100px; left: -100px; }

/* --- SVG Decorative --- */
.section-svg-top { position: absolute; top: -2px; left: 0; right: 0; height: 40px; overflow: hidden; pointer-events: none; z-index: 1; }
.section-svg-bottom { position: absolute; bottom: -2px; left: 0; right: 0; height: 40px; overflow: hidden; pointer-events: none; z-index: 1; }
.section-svg-top svg, .section-svg-bottom svg { width: 100%; height: 100%; fill: var(--bg); }

/* --- SVG Decorations for CTA --- */
.cta-svg-bg { position: absolute; inset: 0; overflow: hidden; pointer-events: none; z-index: 0; }
.cta-svg-bg .gradient-orb { position: absolute; border-radius: 50%; filter: blur(100px); opacity: 0.1; }
.cta-svg-bg .orb-1 { width: 500px; height: 500px; background: var(--accent); top: -200px; right: -100px; }
.cta-svg-bg .orb-2 { width: 350px; height: 350px; background: var(--primary); bottom: -150px; left: -80px; }

/* --- Header --- */
.header { position: fixed; top: 0; left: 0; right: 0; z-index: 1000; background: var(--bg); border-bottom: 1px solid var(--border); height: var(--header-h); transition: all var(--transition); }
.header-scrolled { height: var(--header-h-scroll); box-shadow: var(--shadow-md); backdrop-filter: blur(16px); -webkit-backdrop-filter: blur(16px); background: rgba(255,255,255,0.92); }
[data-theme="dark"] .header-scrolled { background: rgba(11,17,33,0.92); }
.header-inner { display: flex; align-items: center; justify-content: space-between; height: 100%; max-width: var(--container); margin: 0 auto; padding: 0 20px; }
.header-logo { display: flex; align-items: center; gap: 10px; font-family: var(--font-heading); font-weight: 800; font-size: 1.5rem; color: var(--text); text-decoration: none; flex-shrink: 0; }
.header-logo:hover { color: var(--primary); }
.header-logo img { height: 36px; width: auto; }
.header-logo .logo-icon { color: var(--primary); }
.header-logo .logo-text span { color: var(--primary); }
.header-actions { display: flex; align-items: center; gap: 8px; flex-shrink: 0; }

/* --- Navigation --- */
.nav { display: flex; align-items: center; }
.nav-list { display: flex; align-items: center; gap: 2px; }
.nav-list > li { position: relative; }
.nav-list > li > a, .nav-dropdown-toggle { display: flex; align-items: center; gap: 4px; padding: 8px 18px; color: var(--text); font-weight: 500; font-size: 14px; border-radius: var(--radius); transition: all var(--transition-fast); text-decoration: none; background: none; border: none; cursor: pointer; font-family: inherit; }
.nav-list > li > a:hover, .nav-list > li > a.active, .nav-dropdown-toggle:hover { color: var(--primary); background: rgba(var(--primary-rgb), 0.08); }
.nav-dropdown-toggle:focus-visible { outline: 2px solid var(--primary); outline-offset: 2px; }
.nav-list > li > a .fa-chevron-down, .nav-dropdown-toggle .fa-chevron-down { font-size: 10px; transition: transform var(--transition-fast); }
.nav-list > li:hover > a .fa-chevron-down, .nav-list > li.dropdown-open .nav-dropdown-toggle .fa-chevron-down, .nav-list > li:focus-within .nav-dropdown-toggle .fa-chevron-down { transform: rotate(180deg); }
.dropdown-menu { position: absolute; top: 100%; left: 0; min-width: 220px; background: var(--bg-card); border-radius: var(--radius); border: 1px solid var(--border); box-shadow: var(--shadow-lg); padding: 8px; opacity: 0; visibility: hidden; transform: translateY(8px); transition: all var(--transition); z-index: 100; }
.nav-list > li:hover .dropdown-menu, .nav-list > li.dropdown-open .dropdown-menu, .nav-list > li:focus-within .dropdown-menu { opacity: 1; visibility: visible; transform: translateY(4px); }
.dropdown-menu li a { display: block; padding: 10px 16px; color: var(--text); font-size: 14px; font-weight: 500; border-radius: var(--radius-sm); transition: all var(--transition-fast); text-decoration: none; }
.dropdown-menu li a:hover { color: var(--primary); background: rgba(var(--primary-rgb), 0.08); }

/* --- Search Overlay --- */
.search-overlay { position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.85); backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px); z-index: 9999; display: flex; align-items: center; justify-content: center; opacity: 0; visibility: hidden; transition: all var(--transition); }
.search-overlay.active { opacity: 1; visibility: visible; }
.search-overlay-inner { width: 100%; max-width: 600px; padding: 20px; text-align: center; }
.search-overlay-inner h2 { color: #fff; margin-bottom: 24px; font-size: 1.5rem; }
.search-form { position: relative; display: flex; gap: 12px; }
.search-form input { flex: 1; padding: 16px 20px; border: 2px solid rgba(255,255,255,0.2); border-radius: var(--radius); background: rgba(255,255,255,0.1); color: #fff; font-size: 16px; outline: none; transition: border-color var(--transition); }
.search-form input::placeholder { color: rgba(255,255,255,0.5); }
.search-form input:focus { border-color: var(--primary); }
.search-form button { padding: 12px 28px; background: var(--primary); color: #fff; border-radius: var(--radius); font-weight: 600; font-size: 15px; white-space: nowrap; transition: all var(--transition); }
.search-form button:hover { background: var(--primary-dark); transform: translateY(-1px); }
.search-close { position: absolute; top: 24px; right: 24px; width: 48px; height: 48px; background: rgba(255,255,255,0.1); color: #fff; border-radius: var(--radius-full); display: flex; align-items: center; justify-content: center; font-size: 20px; transition: background var(--transition); }
.search-close:hover { background: rgba(255,255,255,0.2); }

/* --- Mobile Menu --- */
.menu-toggle { display: none; width: 44px; height: 44px; align-items: center; justify-content: center; color: var(--text); font-size: 20px; border-radius: var(--radius-sm); }
.menu-toggle:hover { background: rgba(var(--primary-rgb), 0.08); }
.mobile-menu { position: fixed; top: 0; right: -100%; width: 320px; max-width: 85vw; height: 100%; background: var(--bg); z-index: 9998; padding: 24px; overflow-y: auto; transition: right var(--transition); box-shadow: var(--shadow-xl); }
.mobile-menu.active { right: 0; }
.mobile-menu-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 32px; padding-bottom: 16px; border-bottom: 1px solid var(--border); }
.mobile-nav-list li { border-bottom: 1px solid var(--border-light); }
.mobile-nav-list li a { display: flex; align-items: center; justify-content: space-between; padding: 14px 0; color: var(--text); font-weight: 500; font-size: 15px; text-decoration: none; }
.mobile-nav-list li a:hover { color: var(--primary); }
.dropdown-menu-mobile { max-height: 0; overflow: hidden; transition: max-height 0.3s ease; padding-left: 16px; }
.dropdown-menu-mobile.active { max-height: 300px; }
.dropdown-menu-mobile li { border-bottom: none; }
.dropdown-menu-mobile li a { padding: 10px 0; font-size: 14px; color: var(--text-light); }
.mobile-overlay { position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.5); z-index: 9997; opacity: 0; visibility: hidden; transition: all var(--transition); }
.mobile-overlay.active { opacity: 1; visibility: visible; }
.theme-toggle, .search-toggle { width: 44px; height: 44px; display: flex; align-items: center; justify-content: center; color: var(--text); font-size: 16px; border-radius: var(--radius-full); transition: all var(--transition-fast); }
.theme-toggle:hover, .search-toggle:hover { background: rgba(var(--primary-rgb), 0.08); color: var(--primary); }
.theme-toggle .fa-sun { display: none; }
[data-theme="dark"] .theme-toggle .fa-moon { display: none; }
[data-theme="dark"] .theme-toggle .fa-sun { display: inline; }

/* --- Error Page --- */
.error-page { text-align: center; padding: 100px 20px; max-width: 500px; margin: 0 auto; }
.error-page .error-code { font-size: 120px; font-weight: 800; line-height: 1; background: linear-gradient(135deg, var(--primary), var(--accent)); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; margin-bottom: 8px; }
.error-page .error-title { font-size: 1.5rem; margin-bottom: 12px; }
.error-page .error-text { color: var(--text-light); margin-bottom: 32px; }
.error-actions { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; }

/* --- No Posts --- */
.no-posts { text-align: center; padding: 80px 20px; }
.no-posts i { font-size: 48px; color: var(--text-lighter); margin-bottom: 16px; }
.no-posts h3 { margin-bottom: 8px; }
.no-posts p { color: var(--text-light); }

/* --- Modern Enhancements --- */
::-webkit-scrollbar { width: 8px; }
::-webkit-scrollbar-track { background: var(--bg-alt); }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: var(--radius-full); }
::-webkit-scrollbar-thumb:hover { background: var(--text-lighter); }
.gradient-text { background: linear-gradient(135deg, var(--primary), var(--accent)); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
.glass { background: rgba(255,255,255,0.7); backdrop-filter: blur(16px); -webkit-backdrop-filter: blur(16px); border: 1px solid rgba(255,255,255,0.3); }
.glass-dark { background: rgba(15,23,42,0.7); backdrop-filter: blur(16px); -webkit-backdrop-filter: blur(16px); border: 1px solid rgba(255,255,255,0.08); }

/* --- Buttons --- */
.btn { display: inline-flex; align-items: center; justify-content: center; gap: 8px; padding: 12px 28px; font-family: var(--font-body); font-weight: 600; font-size: 15px; line-height: 1; border-radius: var(--radius); transition: all var(--transition); cursor: pointer; border: 2px solid transparent; text-decoration: none; }
.btn-primary { background: var(--primary); color: #fff; border-color: var(--primary); }
.btn-primary:hover { background: var(--primary-dark); border-color: var(--primary-dark); color: #fff; transform: translateY(-2px); box-shadow: 0 8px 24px rgba(var(--primary-rgb),0.35); }
.btn-gradient { background: linear-gradient(135deg, var(--primary), var(--accent)); border: none; color: #fff; position: relative; overflow: hidden; }
.btn-gradient:hover { transform: translateY(-2px); box-shadow: 0 8px 24px rgba(var(--primary-rgb),0.35); color: #fff; }
.btn-gradient::before { content: ''; position: absolute; inset: 0; background: linear-gradient(135deg, var(--accent), var(--primary)); opacity: 0; transition: opacity var(--transition); }
.btn-gradient:hover::before { opacity: 1; }
.btn-gradient span { position: relative; z-index: 1; }
.btn-secondary { background: transparent; color: var(--primary); border-color: var(--primary); }
.btn-secondary:hover { background: var(--primary); color: #fff; transform: translateY(-2px); box-shadow: 0 4px 12px rgba(var(--primary-rgb),0.25); }
.btn-accent { background: var(--accent); color: #fff; border-color: var(--accent); }
.btn-accent:hover { background: var(--accent-dark); color: #fff; transform: translateY(-2px); box-shadow: 0 4px 12px rgba(var(--accent-rgb),0.3); }
.btn-sm { padding: 8px 18px; font-size: 13px; }
.btn-lg { padding: 16px 36px; font-size: 17px; }
.btn-block { width: 100%; }
.btn-outline { background: transparent; color: var(--primary); border-color: var(--primary); }
.btn-outline:hover { background: var(--primary); color: #fff; }

/* --- Hero Section --- */
.hero { position: relative; padding: 120px 0 64px; background: linear-gradient(135deg, var(--secondary) 0%, #1a237e 50%, var(--secondary) 100%); overflow: hidden; }
.hero .container { position: relative; z-index: 1; }
.hero-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: center; }
.hero-content { position: relative; z-index: 1; }
.hero-badge { display: inline-flex; align-items: center; gap: 6px; padding: 6px 16px; background: rgba(var(--primary-rgb),0.15); border: 1px solid rgba(var(--primary-rgb),0.3); border-radius: var(--radius-full); font-size: 13px; font-weight: 600; color: var(--primary-light); margin-bottom: 24px; }
.hero-content h1 { color: #fff; font-size: clamp(2rem, 4.5vw, 3.25rem); margin-bottom: 20px; line-height: 1.12; letter-spacing: -0.02em; }
.hero-content h1 .gradient-text { background: linear-gradient(135deg, var(--primary-light), var(--accent)); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
.hero-content h1 span:not(.gradient-text) { color: var(--accent); }
.hero-content p { color: rgba(255,255,255,0.75); font-size: 1.1rem; line-height: 1.7; margin-bottom: 32px; max-width: 580px; }
.hero-buttons { display: flex; gap: 16px; flex-wrap: wrap; }
.hero-buttons .btn-secondary { color: #fff; border-color: rgba(255,255,255,0.4); }
.hero-buttons .btn-secondary:hover { background: #fff; color: var(--primary); border-color: #fff; }
.hero-trust { display: flex; gap: 24px; flex-wrap: wrap; margin-bottom: 32px; }
.hero-trust span { display: flex; align-items: center; gap: 6px; font-size: 14px; color: rgba(255,255,255,0.7); }
.hero-trust span i { color: var(--accent); font-size: 14px; }
.hero-results { display: flex; gap: 28px; margin-bottom: 32px; flex-wrap: wrap; }
.hero-result-item { text-align: center; position: relative; }
.hero-result-item:not(:last-child)::after { content: ''; position: absolute; right: -14px; top: 10%; height: 80%; width: 1px; background: rgba(255,255,255,0.1); }
.hero-result-num { display: block; font-family: var(--font-heading); font-size: 1.85rem; font-weight: 800; color: #fff; line-height: 1.2; }
.hero-result-label { display: block; font-size: 12px; color: rgba(255,255,255,0.5); text-transform: uppercase; letter-spacing: 0.5px; margin-top: 4px; }

/* Hero Dashboard Visual */
.hero-visual { position: relative; }
.dashboard-card { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); border-radius: var(--radius-lg); overflow: hidden; backdrop-filter: blur(16px); -webkit-backdrop-filter: blur(16px); box-shadow: 0 8px 32px rgba(0,0,0,0.2); }
.dashboard-header { display: flex; gap: 6px; padding: 16px 24px; background: rgba(255,255,255,0.04); border-bottom: 1px solid rgba(255,255,255,0.06); }
.dashboard-dot { width: 10px; height: 10px; border-radius: var(--radius-full); }
.dashboard-dot:nth-child(1) { background: #ef4444; }
.dashboard-dot:nth-child(2) { background: #f59e0b; }
.dashboard-dot:nth-child(3) { background: #22c55e; }
.dashboard-body { padding: 24px; }
.dashboard-metric { margin-bottom: 20px; }
.dashboard-metric:last-of-type { margin-bottom: 24px; }
.metric-label { font-size: 12px; color: rgba(255,255,255,0.5); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 4px; }
.metric-value { font-size: 22px; font-weight: 700; color: #fff; margin-bottom: 8px; }
.metric-bar { height: 6px; background: rgba(255,255,255,0.08); border-radius: 3px; overflow: hidden; }
.metric-bar span { display: block; height: 100%; background: linear-gradient(90deg, var(--primary), var(--accent)); border-radius: 3px; transition: width 1s ease; }
.dashboard-chart { display: flex; align-items: flex-end; gap: 6px; height: 100px; margin-bottom: 20px; padding: 0 4px; }
.chart-bar { flex: 1; background: linear-gradient(to top, var(--primary), var(--accent)); border-radius: 3px 3px 0 0; opacity: 0.7; transition: opacity var(--transition-fast); min-height: 20px; }
.chart-bar:hover { opacity: 1; }
.dashboard-footer { display: flex; justify-content: space-between; padding-top: 16px; border-top: 1px solid rgba(255,255,255,0.06); }
.dashboard-stat { font-size: 13px; color: rgba(255,255,255,0.5); }
.stat-num { display: block; font-size: 18px; font-weight: 700; color: var(--accent); margin-bottom: 2px; }

/* --- Services Section --- */
.services-section { background: var(--bg-alt); position: relative; }
.services-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: var(--gap-lg); }
.service-card { background: var(--bg-card); padding: 40px 32px; border-radius: var(--radius-md); border: 1px solid var(--border); text-align: center; transition: all 0.4s cubic-bezier(0.4,0,0.2,1); position: relative; overflow: hidden; display: flex; flex-direction: column; }
.service-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 4px; background: linear-gradient(90deg, var(--primary), var(--accent)); opacity: 0; transition: opacity 0.4s ease; }
.service-card:hover { transform: translateY(-8px); box-shadow: var(--shadow-xl); border-color: transparent; }
.service-card:hover::before { opacity: 1; }
.service-card::after { content: ''; position: absolute; inset: 0; border-radius: inherit; padding: 1px; background: linear-gradient(135deg, var(--primary), var(--accent), var(--primary)); -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0); -webkit-mask-composite: xor; mask-composite: exclude; opacity: 0; transition: opacity 0.4s ease; pointer-events: none; }
.service-card:hover::after { opacity: 1; }
.service-icon { width: 68px; height: 68px; margin: 0 auto 24px; background: linear-gradient(135deg, rgba(var(--primary-rgb),0.1), rgba(var(--primary-rgb),0.04)); border-radius: var(--radius); display: flex; align-items: center; justify-content: center; font-size: 30px; color: var(--primary); transition: all 0.4s ease; flex-shrink: 0; }
.service-card:hover .service-icon { background: linear-gradient(135deg, var(--primary), var(--primary-dark)); color: #fff; transform: scale(1.1) rotate(-5deg); box-shadow: 0 8px 24px rgba(var(--primary-rgb),0.3); }
.service-card h3 { font-size: 1.15rem; margin-bottom: 12px; }
.service-card p { color: var(--text-light); font-size: 14px; line-height: 1.7; margin-bottom: 20px; flex: 1; }
.service-link { font-size: 14px; font-weight: 600; color: var(--primary); display: inline-flex; align-items: center; gap: 6px; transition: gap 0.3s ease; margin-top: auto; }
.service-link:hover { gap: 10px; }

/* --- Featured Posts Section --- */
.featured-posts { padding: 0 0 48px; }
.featured-posts:has(.featured-grid:empty) { display: none; }
.featured-grid { display: grid; grid-template-columns: 2fr 1fr; gap: var(--gap); }
.featured-main .featured-card { position: relative; border-radius: var(--radius-md); overflow: hidden; height: 100%; min-height: 400px; }
.featured-main .featured-card img { width: 100%; height: 100%; object-fit: cover; position: absolute; inset: 0; transition: transform 0.6s ease; }
.featured-main .featured-card:hover img { transform: scale(1.05); }
.featured-card { position: relative; border-radius: var(--radius-md); overflow: hidden; aspect-ratio: 16/9; }
.featured-card img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.6s ease; }
.featured-card:hover img { transform: scale(1.05); }
.featured-card-overlay { position: absolute; inset: 0; background: linear-gradient(transparent 30%, rgba(0,0,0,0.9)); display: flex; flex-direction: column; justify-content: flex-end; padding: 28px; }
.featured-card-overlay .cat-badge { position: relative; top: auto; left: auto; display: inline-block; width: fit-content; margin-bottom: 10px; }
.featured-card-overlay h3 { color: #fff; font-size: 1.3rem; margin-bottom: 6px; }
.featured-card-overlay h3 a { color: #fff; text-decoration: none; transition: color var(--transition-fast); }
.featured-card-overlay h3 a:hover { color: var(--primary-light); }
.featured-card-overlay .meta { color: rgba(255,255,255,0.6); font-size: 13px; }
.featured-block { display: flex; flex-direction: column; gap: var(--gap); }
.featured-block .featured-card { aspect-ratio: 16/9; flex: 1; }

/* --- About Section --- */
.about-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: center; }
.about-content h2 { margin-bottom: 16px; }
.about-content p { color: var(--text-light); margin-bottom: 16px; }
.about-features { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-top: 24px; }
.about-feature { display: flex; align-items: center; gap: 10px; font-weight: 500; }
.about-feature .fa-check-circle { color: var(--accent); font-size: 18px; }

/* --- Why Choose Us Section --- */
.why-choose-section { background: var(--bg-alt); }
.why-choose-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: center; }
.why-choose-metrics { display: grid; grid-template-columns: 1fr 1fr; gap: var(--gap-sm); }
.metric-card { padding: 28px 20px; border-radius: var(--radius-md); text-align: center; transition: all 0.3s ease; position: relative; overflow: hidden; }
.metric-card::after { content: ''; position: absolute; bottom: 0; left: 20%; right: 20%; height: 3px; border-radius: 2px; transition: all 0.3s ease; }
.metric-card:hover { transform: translateY(-6px); box-shadow: var(--shadow-lg); }
.metric-card:hover::after { left: 10%; right: 10%; }
.metric-primary { background: linear-gradient(135deg, rgba(var(--primary-rgb),0.1), rgba(var(--primary-rgb),0.04)); border: 1px solid rgba(var(--primary-rgb),0.15); }
.metric-primary::after { background: var(--primary); }
.metric-accent { background: linear-gradient(135deg, rgba(16,185,129,0.1), rgba(16,185,129,0.04)); border: 1px solid rgba(16,185,129,0.15); }
.metric-accent::after { background: #059669; }
.metric-secondary { background: linear-gradient(135deg, rgba(37,99,235,0.1), rgba(37,99,235,0.04)); border: 1px solid rgba(37,99,235,0.15); }
.metric-secondary::after { background: var(--primary); }
.metric-success { background: linear-gradient(135deg, rgba(245,158,11,0.1), rgba(245,158,11,0.04)); border: 1px solid rgba(245,158,11,0.15); }
.metric-success::after { background: #d97706; }
.metric-card-icon { font-size: 32px; margin-bottom: 10px; transition: transform 0.3s ease; }
.metric-card:hover .metric-card-icon { transform: scale(1.15); }
.metric-primary .metric-card-icon { color: var(--primary); }
.metric-accent .metric-card-icon { color: #059669; }
.metric-secondary .metric-card-icon { color: var(--primary); }
.metric-success .metric-card-icon { color: #d97706; }
.metric-card-value { font-family: var(--font-heading); font-size: 2rem; font-weight: 800; color: var(--text); line-height: 1.1; }
.metric-card-label { font-size: 13px; color: var(--text-light); margin-top: 6px; font-weight: 500; }
.why-choose-content p { color: var(--text-light); margin-bottom: 16px; }
.why-choose-features { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin: 24px 0; }
.why-feature { display: flex; align-items: center; gap: 8px; font-size: 14px; font-weight: 500; color: var(--text); }
.why-feature i { color: var(--accent); font-size: 16px; }

/* --- Process Section --- */
.process-section { background: var(--bg); position: relative; }
.process-grid { display: grid; grid-template-columns: repeat(6, 1fr); gap: 32px 16px; position: relative; }
.process-grid::before { content: ''; position: absolute; top: 30px; left: calc(8.33% + 16px); right: calc(8.33% + 16px); height: 3px; background: linear-gradient(90deg, var(--primary), var(--accent), var(--primary)); opacity: 0.2; border-radius: 2px; }
.process-step { text-align: center; position: relative; }
.process-step::after { content: '\f054'; font-family: 'Font Awesome 6 Free'; font-weight: 900; position: absolute; top: 22px; right: -14px; color: var(--primary); font-size: 10px; opacity: 0.2; }
.process-step:last-child::after { display: none; }
.process-number { width: 60px; height: 60px; margin: 0 auto 24px; background: linear-gradient(135deg, var(--primary), var(--primary-dark)); color: #fff; border-radius: var(--radius-full); display: flex; align-items: center; justify-content: center; font-family: var(--font-heading); font-size: 1.5rem; font-weight: 800; box-shadow: 0 4px 14px rgba(var(--primary-rgb),0.3); transition: all 0.3s ease; }
.process-step:hover .process-number { transform: scale(1.1); box-shadow: 0 6px 24px rgba(var(--primary-rgb),0.4); }
.process-step h3 { font-size: 1rem; margin-bottom: 8px; }
.process-step p { color: var(--text-light); font-size: 13px; line-height: 1.6; max-width: 180px; margin: 0 auto; }

/* --- Homepage Blog Cards --- */
.blog-posts-section { position: relative; }
.posts-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: var(--gap-lg); }
.blog-content-area { display: block; }
.blog-content-area:has(.main-sidebar) { display: grid; grid-template-columns: 1fr 320px; gap: var(--gap-lg); align-items: start; }
.blog-main { min-width: 0; }
.main-sidebar { width: 100%; }
.post-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-md); overflow: hidden; transition: all 0.4s cubic-bezier(0.4,0,0.2,1); }
.post-card:hover { transform: translateY(-6px); box-shadow: var(--shadow-xl); border-color: var(--primary); }
.post-card-img { display: block; aspect-ratio: 16/9; overflow: hidden; }
.post-card-img img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.6s ease; }
.post-card:hover .post-card-img img { transform: scale(1.08); }
.post-card-body { padding: 20px; position: relative; }
.post-card-cats { margin-bottom: 8px; }
.post-card-cats .cat-badge { position: relative; top: auto; left: auto; display: inline-block; width: auto; }
.post-card-meta { font-size: 13px; color: var(--text-light); margin-bottom: 8px; display: flex; gap: 16px; flex-wrap: wrap; }
.post-card-meta span { display: flex; align-items: center; gap: 4px; }
.read-time-wrap:has(.read-time-card:empty) { display: none; }
.post-card-body h3 { font-size: 1.15rem; margin-bottom: 10px; line-height: 1.4; }
.post-card-body h3 a { color: var(--text); text-decoration: none; }
.post-card-body h3 a:hover { color: var(--primary); }
.post-card-body .snippet { color: var(--text-light); font-size: 14px; line-height: 1.7; margin-bottom: 16px; }
.post-card-footer { display: flex; align-items: center; justify-content: space-between; padding-top: 16px; border-top: 1px solid var(--border); }
.post-card-footer .author { display: flex; align-items: center; gap: 8px; font-size: 13px; color: var(--text-light); }
.post-card-footer .author img { width: 28px; height: 28px; border-radius: var(--radius-full); object-fit: cover; }
.post-card-footer .read-more { font-weight: 600; font-size: 14px; color: var(--primary); display: inline-flex; align-items: center; gap: 6px; text-decoration: none; transition: gap 0.3s ease; }
.post-card-footer .read-more:hover { gap: 10px; }
.pagination { display: flex; align-items: center; justify-content: center; gap: 16px; margin-top: 40px; }
.queryMessage { text-align: center; padding: 24px; margin-bottom: 24px; background: var(--bg-alt); border-radius: var(--radius); }
.query-info { font-size: 14px; font-weight: 600; }
.query-success { color: var(--primary); }
.query-error { color: #dc2626; }

/* --- Testimonials Section --- */
.testimonials-section { background: var(--secondary); color: #fff; position: relative; overflow: hidden; }
.testimonials-section::before { content: ''; position: absolute; inset: 0; background-image: radial-gradient(rgba(255,255,255,0.03) 1px, transparent 1px); background-size: 30px 30px; pointer-events: none; }
.testimonials-section .section-title h2,
.testimonials-section .section-title p { color: #fff; }
.testimonials-section .section-label { color: var(--accent); }
.testimonials-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: var(--gap-lg); }
.testimonial-card { background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.1); border-radius: var(--radius-md); padding: 28px; transition: all 0.4s ease; position: relative; }
.testimonial-card::before { content: '\f10d'; font-family: 'Font Awesome 6 Free'; font-weight: 900; position: absolute; top: 16px; right: 20px; font-size: 36px; color: rgba(255,255,255,0.06); line-height: 1; }
.testimonial-card:hover { transform: translateY(-6px); border-color: rgba(var(--primary-rgb),0.3); box-shadow: 0 12px 40px rgba(0,0,0,0.3); background: rgba(255,255,255,0.09); }
.testimonial-stars { color: #f59e0b; font-size: 13px; margin-bottom: 16px; letter-spacing: 2px; display: flex; gap: 2px; }
.testimonial-text { color: rgba(255,255,255,0.85); font-style: italic; line-height: 1.8; margin-bottom: 24px; font-size: 15px; }
.testimonial-author { display: flex; align-items: center; gap: 12px; padding-top: 16px; border-top: 1px solid rgba(255,255,255,0.06); }
.testimonial-author img { width: 48px; height: 48px; border-radius: var(--radius-full); object-fit: cover; border: 2px solid rgba(255,255,255,0.1); }
.testimonial-author-info strong { color: #fff; font-size: 15px; display: block; }
.testimonial-author-info span { color: rgba(255,255,255,0.5); font-size: 13px; }

/* --- Case Studies Section --- */
.case-studies-section { background: var(--bg); }
.case-studies-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: var(--gap-lg); }
.case-study-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-md); padding: 36px; transition: all 0.4s cubic-bezier(0.4,0,0.2,1); }
.case-study-card:hover { transform: translateY(-6px); box-shadow: var(--shadow-xl); border-color: var(--primary); }
.cs-badge { display: inline-flex; align-items: center; gap: 6px; padding: 4px 14px; border-radius: var(--radius-full); font-size: 12px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 16px; }
.cs-badge-traffic { background: rgba(var(--primary-rgb),0.1); color: var(--primary); }
.cs-badge-rankings { background: rgba(245,158,11,0.1); color: #b45309; }
.cs-badge-revenue { background: rgba(16,185,129,0.1); color: #059669; }
.case-study-card h3 { font-size: 1.15rem; margin-bottom: 16px; }
.cs-stats { display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; margin-bottom: 16px; }
.cs-stat { text-align: center; padding: 12px; background: var(--bg-alt); border-radius: var(--radius-sm); }
.cs-number { font-family: var(--font-heading); font-size: 1.35rem; font-weight: 800; color: var(--primary); display: block; }
.cs-label { font-size: 12px; color: var(--text-light); margin-top: 2px; }
.cs-desc { color: var(--text-light); font-size: 14px; line-height: 1.7; margin-bottom: 20px; }
.cs-link { font-size: 14px; font-weight: 600; color: var(--primary); display: inline-flex; align-items: center; gap: 6px; transition: gap 0.3s ease; }
.cs-link:hover { gap: 10px; }

/* --- FAQ Section --- */
.faq-grid, .faq-list { max-width: 800px; margin: 0 auto; }
.faq-item { border: 1px solid var(--border); border-radius: var(--radius); margin-bottom: 12px; overflow: hidden; transition: all var(--transition-fast); }
.faq-item:hover { border-color: var(--primary); box-shadow: var(--shadow-sm); }
.faq-question { width: 100%; display: flex; align-items: center; justify-content: space-between; padding: 20px 28px; background: var(--bg-card); font-weight: 600; font-size: 15px; color: var(--text); text-align: left; border: none; cursor: pointer; transition: color var(--transition-fast); }
.faq-question:hover { color: var(--primary); }
.faq-question i { font-size: 12px; transition: transform var(--transition-fast); color: var(--text-lighter); }
.faq-question.open i { transform: rotate(180deg); color: var(--primary); }
.faq-answer { padding: 0 28px; max-height: 0; overflow: hidden; transition: all 0.3s ease; color: var(--text-light); font-size: 14px; line-height: 1.8; }
.faq-answer.open { padding: 0 28px 24px; max-height: 500px; }

/* --- YouTube Shorts Section --- */
.youtube-shorts-section { background: var(--bg-alt); }
.youtube-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: var(--gap-lg); }
.video-card { background: var(--bg-card); border-radius: var(--radius-md); overflow: hidden; border: 1px solid var(--border); transition: all 0.4s cubic-bezier(0.4,0,0.2,1); }
.video-card:hover { transform: translateY(-6px); box-shadow: var(--shadow-xl); border-color: var(--primary); }
.video-thumbnail { aspect-ratio: 16/9; overflow: hidden; }
.video-thumbnail img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.6s ease; }
.video-card:hover .video-thumbnail img { transform: scale(1.05); }
.video-info { padding: 20px 24px; }
.video-info h3 { font-size: 1rem; margin-bottom: 8px; }
.video-info p { color: var(--primary); font-size: 13px; font-weight: 600; display: flex; align-items: center; gap: 6px; }

/* --- Newsletter Section --- */
.newsletter-section { background: var(--bg-alt); }
.BlogArchive { padding: 0; }
.BlogArchive #ArchiveList ul li { padding: 8px 0; border-bottom: 1px solid var(--border-light); font-size: 14px; display: flex; justify-content: space-between; align-items: center; }
.BlogArchive #ArchiveList ul li:last-child { border-bottom: none; }
.BlogArchive #ArchiveList a { color: var(--text); text-decoration: none; }
.BlogArchive #ArchiveList a:hover { color: var(--primary); }
.BlogArchive .archivedate-count { color: var(--text-lighter); font-size: 13px; }
.newsletter-inner { max-width: 600px; margin: 0 auto; text-align: center; padding: 36px 40px; background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-lg); box-shadow: var(--shadow); }
.newsletter-inner h2 { margin-bottom: 12px; }
.newsletter-inner p { color: var(--text-light); margin-bottom: 24px; }
.newsletter-form { display: flex; gap: 12px; max-width: 480px; margin: 0 auto; }
.newsletter-form input { flex: 1; padding: 14px 18px; border: 1.5px solid var(--border); border-radius: var(--radius); font-size: 14px; color: var(--text); background: var(--bg); outline: none; transition: all var(--transition-fast); }
.newsletter-form input:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(var(--primary-rgb),0.08); }
.newsletter-form input:hover { border-color: var(--text-lighter); }
.newsletter-form button { padding: 14px 28px; background: var(--primary); color: #fff; border: none; border-radius: var(--radius); font-weight: 600; font-size: 14px; cursor: pointer; transition: all var(--transition); white-space: nowrap; display: flex; align-items: center; gap: 8px; }
.newsletter-form button:hover { background: var(--primary-dark); transform: translateY(-1px); }

/* --- CTA Section --- */
.cta-section { position: relative; background: linear-gradient(135deg, var(--secondary) 0%, #1a237e 50%, var(--secondary) 100%); overflow: hidden; }
.cta-section::before { content: ''; position: absolute; top: -200px; right: -150px; width: 500px; height: 500px; background: radial-gradient(circle, rgba(var(--accent-rgb),0.15), transparent 70%); border-radius: 50%; pointer-events: none; }
.cta-section::after { content: ''; position: absolute; bottom: -150px; left: -100px; width: 400px; height: 400px; background: radial-gradient(circle, rgba(var(--primary-rgb),0.12), transparent 70%); border-radius: 50%; pointer-events: none; }
.cta-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 32px; align-items: stretch; }
.cta-content { display: flex; flex-direction: column; justify-content: center; position: relative; z-index: 1; }
.cta-content h2 { color: #fff; font-size: clamp(1.75rem, 3.5vw, 2.5rem); margin-bottom: 16px; }
.cta-content h2 .highlight { color: var(--accent); }
.cta-content p { color: rgba(255,255,255,0.75); font-size: 1.1rem; line-height: 1.8; margin-bottom: 24px; }
.cta-benefits { list-style: none; margin-bottom: 24px; display: flex; flex-direction: column; gap: 12px; }
.cta-benefits li { color: rgba(255,255,255,0.9); font-size: 14px; display: flex; align-items: center; gap: 10px; padding: 8px 14px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.06); border-radius: 8px; transition: all 0.3s ease; }
.cta-benefits li:hover { background: rgba(255,255,255,0.08); border-color: rgba(255,255,255,0.12); transform: translateX(4px); }
.cta-benefits li i { color: var(--accent); font-size: 16px; flex-shrink: 0; }
.cta-rating { display: flex; align-items: center; gap: 4px; color: #f59e0b; font-size: 14px; margin-bottom: 12px; }
.cta-rating span { color: rgba(255,255,255,0.6); font-size: 13px; margin-left: 4px; }
.cta-trust-badges { display: flex; gap: 16px; flex-wrap: wrap; margin-top: 20px; padding-top: 16px; border-top: 1px solid rgba(255,255,255,0.08); }
.cta-trust-badges span { display: flex; align-items: center; gap: 6px; color: rgba(255,255,255,0.5); font-size: 13px; }
.cta-trust-badges span i { color: var(--accent); font-size: 14px; }
.cta-contact-info { display: flex; gap: 20px; flex-wrap: wrap; margin-top: 16px; padding-top: 16px; border-top: 1px solid rgba(255,255,255,0.08); }
.cta-contact-info span { display: flex; align-items: center; gap: 8px; color: rgba(255,255,255,0.6); font-size: 13px; transition: color 0.3s ease; }
.cta-contact-info span:hover { color: rgba(255,255,255,0.9); }
.cta-contact-info span i { width: 28px; height: 28px; display: flex; align-items: center; justify-content: center; background: rgba(255,255,255,0.06); border-radius: var(--radius-full); color: var(--accent); font-size: 12px; transition: all 0.3s ease; }
.cta-contact-info span:hover i { background: rgba(var(--accent-rgb),0.15); }
.cta-buttons { display: flex; gap: 16px; flex-wrap: wrap; }
.cta-buttons .btn-secondary { color: #fff; border-color: rgba(255,255,255,0.4); }
.cta-buttons .btn-secondary:hover { background: #fff; color: var(--primary); border-color: #fff; }
.cta-form { display: flex; align-items: stretch; position: relative; z-index: 1; }

/* Form Card */
.cta-form-card { background: var(--bg-card); border-radius: 16px; padding: 32px; box-shadow: 0 16px 48px rgba(0,0,0,0.2); position: relative; overflow: hidden; }
.cta-form-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 4px; background: linear-gradient(90deg, var(--primary), var(--accent), var(--primary)); border-radius: 16px 16px 0 0; }
.cta-form-card::after { content: ''; position: absolute; inset: 0; background-image: radial-gradient(rgba(var(--primary-rgb),0.03) 1px, transparent 1px); background-size: 20px 20px; pointer-events: none; }
.cta-form-badge { display: inline-flex; align-items: center; gap: 6px; padding: 6px 16px; background: linear-gradient(135deg, rgba(var(--primary-rgb),0.1), rgba(var(--primary-rgb),0.04)); border: 1px solid rgba(var(--primary-rgb),0.2); border-radius: var(--radius-full); font-size: 12px; font-weight: 600; color: var(--primary); margin-bottom: 16px; }
.cta-form-card h3 { font-size: 1.35rem; margin-bottom: 8px; position: relative; z-index: 1; }
.cta-form-card > p { color: var(--text-light); font-size: 13px; margin-bottom: 20px; line-height: 1.5; position: relative; z-index: 1; }
.cta-form-card .contact-form-widget .widget-content { padding: 0; position: relative; z-index: 1; }
.cta-form-card .contact-form-widget form { display: flex; flex-direction: column; gap: 12px; }
.cta-form-card .contact-form-widget .contact-form-name-label,
.cta-form-card .contact-form-widget .contact-form-email-label,
.cta-form-card .contact-form-widget .contact-form-email-message-label { display: none; }

/* Form Fields */
.cta-form-card .contact-form-widget .contact-form-name,
.cta-form-card .contact-form-widget .contact-form-email { width: 100%; padding: 14px 16px; border: 1.5px solid var(--border); border-radius: 10px; font-size: 14px; color: var(--text); background: var(--bg); outline: none; transition: all 0.25s ease; box-sizing: border-box; font-family: inherit; }
.cta-form-card .contact-form-widget .contact-form-name:hover,
.cta-form-card .contact-form-widget .contact-form-email:hover { border-color: var(--text-lighter); }
.cta-form-card .contact-form-widget .contact-form-name:focus,
.cta-form-card .contact-form-widget .contact-form-email:focus { border-color: var(--primary); box-shadow: 0 0 0 4px rgba(var(--primary-rgb),0.12); }
.cta-form-card .contact-form-widget .contact-form-name::placeholder,
.cta-form-card .contact-form-widget .contact-form-email::placeholder { color: var(--text-lighter); }

/* Textarea */
.cta-form-card .contact-form-widget .contact-form-email-message { width: 100%; padding: 14px 16px; border: 1.5px solid var(--border); border-radius: 10px; font-size: 14px; color: var(--text); background: var(--bg); outline: none; transition: all 0.25s ease; box-sizing: border-box; font-family: inherit; resize: vertical; min-height: 80px; }
.cta-form-card .contact-form-widget .contact-form-email-message:hover { border-color: var(--text-lighter); }
.cta-form-card .contact-form-widget .contact-form-email-message:focus { border-color: var(--primary); box-shadow: 0 0 0 4px rgba(var(--primary-rgb),0.12); }
.cta-form-card .contact-form-widget .contact-form-email-message::placeholder { color: var(--text-lighter); }

/* Submit Button */
.cta-form-card .contact-form-widget .contact-form-button { width: 100%; height: 50px; background: linear-gradient(135deg, var(--primary), #1D4ED8); color: #fff; border: none; border-radius: 10px; font-weight: 700; font-size: 16px; cursor: pointer; transition: all 0.25s ease; display: flex; align-items: center; justify-content: center; gap: 10px; letter-spacing: 0.01em; }
.cta-form-card .contact-form-widget .contact-form-button:hover { background: linear-gradient(135deg, #1D4ED8, #1E40AF); transform: translateY(-2px); box-shadow: 0 8px 28px rgba(var(--primary-rgb),0.4); }
.cta-form-card .contact-form-widget .contact-form-button:active { transform: translateY(0); }

/* Messages - :empty rule placed LAST and with matching specificity so it always wins
   over the colored background/border rules below when the message paragraph has no text.
   (Previously these stayed visible as blank colored bars even with nothing inside.) */
.cta-form-card .contact-form-widget .contact-form-error-message,
.cta-form-card .contact-form-widget .contact-form-success-message { padding: 10px 14px; font-size: 12px; border-radius: 8px; margin-top: 8px; }
.cta-form-card .contact-form-widget .contact-form-error-message { background: rgba(220,38,38,0.08); border: 1px solid rgba(220,38,38,0.2); color: #dc2626; }
.cta-form-card .contact-form-widget .contact-form-success-message { background: rgba(22,163,74,0.08); border: 1px solid rgba(22,163,74,0.2); color: #16a34a; }
.cta-form-card .contact-form-widget .contact-form-error-message:empty,
.cta-form-card .contact-form-widget .contact-form-success-message:empty { display: none; padding: 0; margin: 0; border: 0; background: none; }

/* --- Contact Section --- */
.contact-grid { display: grid; grid-template-columns: 1fr 1fr; gap: var(--gap-lg); align-items: start; }
.contact-info { display: flex; flex-direction: column; gap: 20px; }
.contact-info-item { display: flex; align-items: flex-start; gap: 16px; padding: 20px; background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-md); transition: all var(--transition); }
.contact-info-item:hover { border-color: var(--primary); box-shadow: var(--shadow); }
.contact-info-item i { width: 44px; height: 44px; display: flex; align-items: center; justify-content: center; background: rgba(var(--primary-rgb),0.08); color: var(--primary); border-radius: var(--radius); font-size: 18px; flex-shrink: 0; }
.contact-info-item h4 { font-size: 14px; margin-bottom: 2px; }
.contact-info-item p { color: var(--text-light); font-size: 14px; }
.contact-form-wrapper { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-lg); padding: 36px; box-shadow: var(--shadow); }
.contact-form { display: flex; flex-direction: column; gap: 16px; }
.form-group { width: 100%; }
.form-input { width: 100%; padding: 14px 16px; border: 1.5px solid var(--border); border-radius: var(--radius); font-size: 14px; color: var(--text); background: var(--bg); outline: none; transition: all var(--transition-fast); font-family: inherit; }
.form-input:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(var(--primary-rgb),0.08); }
.form-input:hover { border-color: var(--text-lighter); }
.form-input::placeholder { color: var(--text-lighter); }
textarea.form-input { resize: vertical; min-height: 100px; }

/* --- Contact Form Widget --- */
.contact-form-widget .widget-content { padding: 0; }
.contact-form-widget form { display: flex; flex-direction: column; gap: 10px; }
.contact-form-name, .contact-form-email { width: 100%; padding: 13px 16px; border: 1.5px solid var(--border); border-radius: 8px; font-size: 14px; color: var(--text); background: var(--bg); outline: none; transition: all 0.2s ease; box-sizing: border-box; font-family: inherit; }
.contact-form-name:hover, .contact-form-email:hover { border-color: var(--text-lighter); }
.contact-form-name:focus, .contact-form-email:focus,
.contact-form-email-message:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(var(--primary-rgb),0.1); }
.contact-form-name::placeholder, .contact-form-email::placeholder,
.contact-form-email-message::placeholder { color: var(--text-lighter); }
.contact-form-email-message { width: 100%; padding: 13px 16px; border: 1.5px solid var(--border); border-radius: 8px; font-size: 14px; color: var(--text); background: var(--bg); outline: none; transition: all 0.2s ease; font-family: inherit; resize: vertical; min-height: 80px; box-sizing: border-box; }
.contact-form-button { padding: 13px 28px; background: var(--primary); color: #fff; border: none; border-radius: 8px; font-weight: 600; font-size: 15px; cursor: pointer; transition: all var(--transition); font-family: inherit; }
.contact-form-button:hover { background: var(--primary-dark); transform: translateY(-1px); box-shadow: 0 4px 12px rgba(var(--primary-rgb),0.3); }
.contact-form-error-message, .contact-form-success-message { font-size: 13px; padding: 8px 12px; border-radius: var(--radius-sm); margin-top: 4px; }
.contact-form-error-message:empty, .contact-form-success-message:empty { display: none; padding: 0; margin: 0; border: 0; }
.contact-form-error-message { color: #dc2626; background: rgba(220,38,38,0.08); border: 1px solid rgba(220,38,38,0.15); }
.contact-form-success-message { color: #16a34a; background: rgba(22,163,74,0.08); border: 1px solid rgba(22,163,74,0.15); }

/* --- Sticky CTA Bar --- */
.sticky-cta-bar { position: fixed; bottom: 0; left: 0; right: 0; z-index: 9990; background: var(--secondary); color: #fff; padding: 14px 20px; transform: translateY(100%); transition: transform var(--transition); }
.sticky-cta-bar.visible { transform: translateY(0); }
.sticky-cta-content { display: flex; align-items: center; justify-content: center; gap: 16px; flex-wrap: wrap; max-width: var(--container); margin: 0 auto; position: relative; }
.sticky-cta-text { font-size: 14px; font-weight: 500; margin: 0; }
.sticky-cta-text strong { color: var(--accent); }
.sticky-cta-bar .btn { font-size: 13px; padding: 10px 20px; flex-shrink: 0; }
.sticky-cta-close { position: absolute; right: 0; top: 50%; transform: translateY(-50%); color: rgba(255,255,255,0.4); font-size: 20px; cursor: pointer; transition: color var(--transition-fast); background: none; border: none; padding: 4px; line-height: 1; }
.sticky-cta-close:hover { color: #fff; }

/* --- Archive / Feed View --- */
#feed-view { flex: 1; min-width: 0; }
.main-wrapper { display: flex; flex-direction: column; min-height: calc(100vh - var(--header-h)); margin-top: var(--header-h); }
.main-content { width: 100%; max-width: var(--container); margin: 0 auto; padding: 0 20px; flex: 1; display: flex; flex-direction: column; }
.feed-view .main-content { display: grid; grid-template-columns: 1fr 300px; gap: var(--gap-lg); padding: 40px 20px; }
.sidebar-container { width: 300px; flex-shrink: 0; }
.post-filter-wrap { display: grid; grid-template-columns: 1fr 300px; gap: var(--gap-lg); padding: 40px 0; }
.item-post-wrap { max-width: var(--container-narrow); margin: 0 auto; padding: 40px 0; }

/* --- Sidebar --- */
.sidebar { display: flex; flex-direction: column; gap: var(--gap-lg); }
.sidebar-sticky { position: sticky; top: calc(var(--header-h) + 20px); }
.sidebar-widget { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-md); overflow: hidden; transition: all var(--transition-fast); }
.sidebar-widget:has(.widget-content:empty) { display: none; }
.sidebar-widget:hover { border-color: var(--primary); }
.widget-title { display: flex; align-items: center; gap: 10px; padding: 18px 24px; font-family: var(--font-heading); font-size: 1rem; font-weight: 700; border-bottom: 1px solid var(--border); }
.widget-title::before { content: ''; width: 3px; height: 18px; background: var(--primary); border-radius: 2px; }
.widget-content { padding: 20px 24px; }
.popular-post-item { display: flex; gap: 12px; padding: 12px 0; border-bottom: 1px solid var(--border-light); transition: all var(--transition-fast); }
.popular-post-item:hover { padding-left: 4px; }
.popular-post-item:last-child { border-bottom: none; }
.popular-post-img { width: 72px; height: 72px; border-radius: var(--radius-sm); object-fit: cover; flex-shrink: 0; }
.popular-post-info h4 { font-size: 14px; line-height: 1.4; margin-bottom: 4px; }
.popular-post-info h4 a { color: var(--text); text-decoration: none; }
.popular-post-info h4 a:hover { color: var(--primary); }
.popular-post-info .meta { font-size: 12px; color: var(--text-lighter); }
.cloud-label-widget-content { display: flex; flex-wrap: wrap; gap: 6px; }
.cloud-label-widget-content a { padding: 5px 14px; background: var(--bg-alt); border-radius: var(--radius-full); font-size: 12px; color: var(--text-light); text-decoration: none; transition: all var(--transition-fast); border: 1px solid transparent; }
.cloud-label-widget-content a:hover { background: var(--primary); color: #fff; border-color: var(--primary); }
.sidebar .search-form input { border: 1.5px solid var(--border); background: var(--bg); color: var(--text); padding: 12px 16px; border-radius: var(--radius); }
.sidebar .search-form input:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(var(--primary-rgb),0.08); }
.sidebar .search-form input::placeholder { color: var(--text-lighter); }
.sidebar .search-form button { padding: 12px 16px; background: var(--primary); color: #fff; border-radius: var(--radius); transition: all var(--transition-fast); }
.sidebar .search-form button:hover { background: var(--primary-dark); }

/* --- Single Post --- */
.item-post { max-width: var(--container-narrow); margin: 0 auto; }
.post-inner-area { padding: 0; }
.post-featured-image { margin-bottom: 24px; border-radius: var(--radius-md); overflow: hidden; box-shadow: var(--shadow); }
.post-featured-image img { width: 100%; height: auto; display: block; }
.post-single { max-width: var(--container-narrow); margin: 0 auto; padding: 100px 20px 48px; }
.post-single-header { margin-bottom: 36px; }
.post-single-header h1 { font-size: clamp(1.75rem, 3.5vw, 2.5rem); margin-bottom: 16px; line-height: 1.3; letter-spacing: -0.02em; }
.post-single-meta { display: flex; align-items: center; gap: 20px; flex-wrap: wrap; font-size: 14px; color: var(--text-light); padding-bottom: 24px; border-bottom: 1px solid var(--border); }
.author-img { width: 48px; height: 48px; border-radius: var(--radius-full); object-fit: cover; border: 2px solid var(--border); }
.post-single-featured-img { margin-bottom: 32px; border-radius: var(--radius-md); overflow: hidden; box-shadow: var(--shadow); }
.post-single-featured-img img { width: 100%; height: auto; display: block; }
.post-tags { display: flex; flex-wrap: wrap; gap: 8px; margin-top: 32px; padding-top: 24px; border-top: 1px solid var(--border); }
.post-tags a { display: inline-flex; align-items: center; gap: 4px; padding: 6px 14px; background: var(--bg-alt); border-radius: var(--radius-full); font-size: 13px; color: var(--text-light); text-decoration: none; transition: all var(--transition-fast); border: 1px solid transparent; }
.post-tags a:hover { background: var(--primary); color: #fff; border-color: var(--primary); }
.post-share { display: flex; align-items: center; gap: 12px; margin-top: 24px; padding-top: 24px; border-top: 1px solid var(--border); }
.post-share span { font-weight: 600; font-size: 14px; color: var(--text); }
.post-share a { width: 40px; height: 40px; display: flex; align-items: center; justify-content: center; border-radius: var(--radius-full); background: var(--bg-alt); color: var(--text-light); font-size: 16px; transition: all var(--transition-fast); text-decoration: none; }
.post-share a:hover { background: var(--primary); color: #fff; transform: translateY(-2px); }
.post-navigation { display: grid; grid-template-columns: 1fr 1fr; gap: var(--gap); margin-top: 40px; padding-top: 32px; border-top: 1px solid var(--border); }
.post-nav-link { padding: 20px; background: var(--bg-alt); border-radius: var(--radius-md); text-decoration: none; transition: all var(--transition-fast); border: 1px solid transparent; }
.post-nav-link:hover { background: rgba(var(--primary-rgb),0.08); border-color: rgba(var(--primary-rgb),0.2); }
.post-nav-link .nav-label { display: flex; align-items: center; gap: 6px; font-size: 13px; color: var(--text-lighter); margin-bottom: 4px; }
.post-nav-link.next .nav-label { justify-content: flex-end; }
.post-body { font-size: 17px; line-height: 1.85; color: var(--text); }
.post-body h2, .post-body h3, .post-body h4 { margin-top: 36px; margin-bottom: 16px; }
.post-body p { margin-bottom: 1.2em; }
.post-body a { text-decoration: underline; text-underline-offset: 2px; }
.post-body blockquote { border-left: 4px solid var(--primary); padding: 20px 28px; margin: 24px 0; background: var(--bg-alt); border-radius: 0 var(--radius-sm) var(--radius-sm) 0; font-style: italic; color: var(--text-light); }
.post-body ul, .post-body ol { margin: 16px 0; padding-left: 24px; }
.post-body ul { list-style: disc; }
.post-body ol { list-style: decimal; }
.post-body li { margin-bottom: 8px; }
.post-body img { border-radius: var(--radius); margin: 24px auto; max-width: 100%; box-shadow: var(--shadow-sm); }
.post-body pre { background: var(--secondary); color: #e2e8f0; padding: 24px; border-radius: var(--radius); overflow-x: auto; font-size: 14px; line-height: 1.6; margin: 24px 0; }
.post-body code { background: var(--bg-alt); padding: 2px 8px; border-radius: 4px; font-size: 14px; font-family: 'Fira Code', monospace; }
.post-body pre code { background: transparent; padding: 0; }

/* --- Table of Contents (hidden by default; JS reveals only when 2+ headings found) --- */
.toc-container { display: none; margin: 24px 0; padding: 20px 24px; background: var(--bg-alt); border: 1px solid var(--border); border-radius: var(--radius-md); }
.toc-container.has-toc { display: block; }
.toc-container details > summary { cursor: pointer; font-family: var(--font-heading); font-weight: 700; font-size: 1.1rem; color: var(--text); list-style: none; display: flex; align-items: center; justify-content: space-between; }
.toc-container details > summary::-webkit-details-marker { display: none; }
.toc-container details > summary::after { content: '\f078'; font-family: 'Font Awesome 6 Free'; font-weight: 900; font-size: 12px; color: var(--text-lighter); transition: transform var(--transition-fast); }
.toc-container details[open] > summary::after { transform: rotate(180deg); }
.toc-container ul { margin-top: 12px; list-style: none; }
.toc-container li { margin: 4px 0; }
.toc-container a { font-size: 14px; color: var(--primary); text-decoration: none; }
.toc-container a:hover { text-decoration: underline; }

/* --- Comments --- */
.comments-section { margin-top: 48px; padding-top: 32px; border-top: 1px solid var(--border); }
.comments-section h3 { font-size: 1.25rem; margin-bottom: 24px; display: flex; align-items: center; gap: 8px; }

/* --- Main Layout --- */
#center-container { position: relative; float: left; width: 100%; overflow: hidden; padding: 0; margin: 0; }
.outer-container { display: flex; justify-content: space-between; }

/* --- Pagination --- */
.blog-pager { display: flex; align-items: center; justify-content: center; gap: 16px; margin: 40px 0; }
.blog-pager a { display: inline-flex; align-items: center; gap: 8px; padding: 12px 24px; border: 1.5px solid var(--border); border-radius: var(--radius); font-size: 14px; font-weight: 600; color: var(--text); text-decoration: none; transition: all var(--transition-fast); }
.blog-pager a:hover { border-color: var(--primary); color: var(--primary); background: rgba(var(--primary-rgb),0.04); }

/* --- Footer --- */
.footer, #footer-section { background: var(--secondary); color: rgba(255,255,255,0.8); padding: 48px 0 0; position: relative; overflow: hidden; }
.footer::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 1px; background: linear-gradient(90deg, transparent, rgba(var(--primary-rgb),0.3), rgba(var(--accent-rgb),0.3), transparent); }
.footer::after { content: ''; position: absolute; top: -120px; right: -100px; width: 400px; height: 400px; background: radial-gradient(circle, rgba(var(--primary-rgb),0.06), transparent 70%); border-radius: 50%; pointer-events: none; }
.footer-grid, .footer-widgets { display: grid; grid-template-columns: 1.6fr 1fr 1fr 1fr 1fr; gap: var(--gap-lg); position: relative; z-index: 1; }
.footer-brand p { margin-top: 16px; font-size: 14px; line-height: 1.8; color: rgba(255,255,255,0.5); max-width: 320px; }
.footer-logo { display: flex; align-items: center; gap: 10px; font-family: var(--font-heading); font-weight: 800; font-size: 1.4rem; color: #fff; text-decoration: none; }
.footer-logo:hover { color: var(--primary-light); }
.footer-logo span { color: var(--primary); }
.footer h4, .footer-heading { color: #fff; font-size: 1rem; margin-bottom: 20px; letter-spacing: 0.03em; position: relative; padding-bottom: 12px; }
.footer h4::after, .footer-heading::after { content: ''; position: absolute; bottom: 0; left: 0; width: 32px; height: 2.5px; background: linear-gradient(90deg, var(--primary), var(--accent)); border-radius: 2px; }
.footer-links li { margin-bottom: 10px; }
.footer-links li a { color: rgba(255,255,255,0.55); font-size: 14px; display: inline-flex; align-items: center; gap: 6px; text-decoration: none; transition: all var(--transition-fast); }
.footer-links li a:hover { color: var(--primary-light); transform: translateX(4px); }
.footer-links.contact-info li { display: flex; align-items: center; gap: 10px; color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 14px; }
.footer-links.contact-info li i { width: 32px; height: 32px; display: flex; align-items: center; justify-content: center; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.06); border-radius: var(--radius-full); color: var(--accent); font-size: 13px; flex-shrink: 0; transition: all var(--transition-fast); }
.footer-links.contact-info li:hover i { background: rgba(var(--accent-rgb),0.1); border-color: rgba(var(--accent-rgb),0.2); transform: scale(1.05); }
.footer-social { display: flex; gap: 10px; margin-top: 24px; }
.footer-social a { width: 42px; height: 42px; display: flex; align-items: center; justify-content: center; border-radius: var(--radius-full); background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.06); color: rgba(255,255,255,0.6); font-size: 16px; transition: all var(--transition-fast); text-decoration: none; }
.footer-social a:hover { background: var(--primary); color: #fff; transform: translateY(-3px); border-color: var(--primary); box-shadow: 0 4px 12px rgba(var(--primary-rgb),0.3); }
.footer-social a[aria-label='Facebook']:hover { background: #1877F2; border-color: #1877F2; box-shadow: 0 4px 12px rgba(24,119,242,0.3); }
.footer-social a[aria-label='LinkedIn']:hover { background: #0A66C2; border-color: #0A66C2; box-shadow: 0 4px 12px rgba(10,102,194,0.3); }
.footer-social a[aria-label='Instagram']:hover { background: linear-gradient(135deg, #833AB4, #E1306C, #FCAF45); border-color: #E1306C; box-shadow: 0 4px 12px rgba(225,48,108,0.3); }
.footer-social a[aria-label='YouTube']:hover { background: #FF0000; border-color: #FF0000; box-shadow: 0 4px 12px rgba(255,0,0,0.3); }
.footer-social a[aria-label='Linktree']:hover { background: #43E660; border-color: #43E660; color: #1a1a1a; box-shadow: 0 4px 12px rgba(67,230,96,0.3); }
.footer-bottom { margin-top: 32px; padding: 20px 0; border-top: 1px solid rgba(255,255,255,0.06); display: flex; align-items: center; justify-content: space-between; font-size: 13px; color: rgba(255,255,255,0.4); position: relative; z-index: 1; }
.footer-bottom a { color: rgba(255,255,255,0.6); text-decoration: none; transition: color var(--transition-fast); }
.footer-bottom a:hover { color: var(--primary-light); }

/* --- WhatsApp FAB --- */
.whatsapp-btn, .whatsapp-fab { position: fixed; bottom: 24px; right: 24px; z-index: 999; width: 56px; height: 56px; background: #25D366; color: #fff; border-radius: var(--radius-full); display: flex; align-items: center; justify-content: center; font-size: 28px; box-shadow: 0 6px 16px rgba(37,211,102,0.4); transition: all var(--transition); text-decoration: none; }
.whatsapp-btn:hover, .whatsapp-fab:hover { transform: scale(1.1) translateY(-2px); color: #fff; box-shadow: 0 8px 24px rgba(37,211,102,0.5); }
.back-to-top { position: fixed; bottom: 90px; right: 24px; z-index: 998; width: 44px; height: 44px; background: var(--primary); color: #fff; border-radius: var(--radius-full); display: flex; align-items: center; justify-content: center; font-size: 18px; box-shadow: var(--shadow-md); transition: all var(--transition); cursor: pointer; border: none; opacity: 0; visibility: hidden; }
.back-to-top.visible { opacity: 1; visibility: visible; }
.back-to-top:hover { background: var(--primary-dark); transform: translateY(-3px); box-shadow: var(--shadow-lg); }
.sticky-cta-bar.visible ~ .whatsapp-btn, .sticky-cta-bar.visible ~ .whatsapp-fab { bottom: 84px; }
.sticky-cta-bar.visible ~ .back-to-top { bottom: 150px; }

/* --- Animations (visible by default, enhanced by JS) --- */
.animate-on-scroll { opacity: 1; transform: none; transition: opacity 0.5s cubic-bezier(0.4,0,0.2,1), transform 0.5s cubic-bezier(0.4,0,0.2,1); }
html.js-enabled .animate-on-scroll { opacity: 0; transform: translateY(20px); }
html.js-enabled .animate-on-scroll.animated { opacity: 1; transform: translateY(0); }
@media (prefers-reduced-motion: reduce) { html.js-enabled .animate-on-scroll { opacity: 1; transform: none; transition: none; } }
html:not(.js-enabled) .animate-on-scroll { opacity: 1; transform: none; }

/* --- Media Queries --- */
@media (max-width: 1024px) {
  .cta-grid { grid-template-columns: 1fr; }
  .cta-content { text-align: center; }
  .cta-content p { margin: 0 auto 16px; }
  .cta-buttons { justify-content: center; }
  .cta-benefits { align-items: center; text-align: left; display: inline-flex; flex-direction: column; }
  .cta-benefits li { font-size: 13px; }
  .cta-contact-info { justify-content: center; }
  .hero-grid { grid-template-columns: 1fr; }
  .hero-content { text-align: center; }
  .hero-content p { margin: 0 auto 32px; }
  .hero-buttons { justify-content: center; }
  .hero-results { justify-content: center; }
  .hero-result-item:not(:last-child)::after { display: none; }
  .process-grid { grid-template-columns: repeat(3, 1fr); }
  .process-grid::before { display: none; }
  .process-step::after { display: none; }
  .posts-grid { grid-template-columns: repeat(2, 1fr); }
  .about-stats { grid-template-columns: repeat(2, 1fr); }
  .footer-grid, .footer-widgets { grid-template-columns: 1fr 1fr; }
  .featured-grid { grid-template-columns: 1fr; }
  .blog-content-area:has(.main-sidebar) { grid-template-columns: 1fr; }
  .lead-magnets-grid { grid-template-columns: repeat(2, 1fr); }
  .case-studies-grid { grid-template-columns: repeat(2, 1fr); }
  .why-choose-grid { grid-template-columns: 1fr; gap: 32px; }
  .about-grid { grid-template-columns: 1fr; }
}
@media (max-width: 768px) {
  :root { --header-h: 64px; }
  .nav { display: none; }
  .menu-toggle { display: flex; }
  .section { padding: 36px 0; }
  .hero { padding: 80px 0 40px; }
  .hero-grid { grid-template-columns: 1fr; }
  .hero-content { text-align: center; }
  .hero-content p { margin: 0 auto 24px; max-width: 500px; }
  .hero-buttons { flex-direction: column; }
  .hero-buttons .btn { width: 100%; text-align: center; }
  .hero-trust { justify-content: center; gap: 12px; }
  .hero-trust span { font-size: 12px; }
  .hero-results { justify-content: center; gap: 12px; }
  .hero-result-item:not(:last-child)::after { display: none; }
  .hero-result-num { font-size: 1.3rem; }
  .hero-result-label { font-size: 10px; }
  .dashboard-card { max-width: 400px; margin: 0 auto; }
  .about-grid { grid-template-columns: 1fr; }
  .about-features { grid-template-columns: 1fr; }
  .about-stats { grid-template-columns: 1fr 1fr; }
  .process-grid { grid-template-columns: repeat(2, 1fr); }
  .process-grid::before { display: none; }
  .process-step::after { display: none; }
  .posts-grid { grid-template-columns: 1fr; gap: var(--gap); }
  .post-card-body { padding: 16px; }
  .case-studies-grid { grid-template-columns: 1fr; }
  .lead-magnets-grid { grid-template-columns: 1fr; }
  .cta-grid { grid-template-columns: 1fr; }
  .cta-content { text-align: center; }
  .cta-content p { margin: 0 auto 16px; }
  .cta-buttons { justify-content: center; }
  .cta-benefits { align-items: center; text-align: left; }
  .cta-contact-info { justify-content: center; }
  .cta-form-card { padding: 20px; }
  .footer-grid, .footer-widgets { grid-template-columns: 1fr; }
  .footer-bottom { flex-direction: column; gap: 8px; text-align: center; }
  .featured-posts { padding: 0 0 36px; }
  .featured-grid { grid-template-columns: 1fr; }
  .featured-main .featured-card { min-height: 250px; }
  .newsletter-form { flex-direction: column; }
  .post-navigation { grid-template-columns: 1fr; }
  .sticky-cta-bar .sticky-cta-text { font-size: 12px; }
  .sticky-cta-bar .btn { font-size: 12px; padding: 8px 16px; }
  .post-single-meta { gap: 12px; font-size: 13px; }
  .post-cta-box { padding: 24px 20px; }
  .post-cta-content h3 { font-size: 1.2rem; }
  .toc-container { padding: 16px; }
  .widget-title { padding: 14px 16px; }
  .widget-content { padding: 16px; }
  .btn-lg { padding: 14px 28px; font-size: 15px; }
  .container { padding: 0 16px; }
  .section-cta { margin-top: 24px; }
  .pagination { margin-top: 32px; }
  .blog-pager { margin: 32px 0; }
  .faq-question { padding: 16px 20px; font-size: 14px; }
  .faq-answer.open { padding: 0 20px 16px; }
  .newsletter-inner { padding: 28px 20px; }
  .why-choose-metrics { grid-template-columns: 1fr 1fr; gap: var(--gap-sm); }
  .metric-card { padding: 18px 14px; }
  .metric-card-value { font-size: 1.4rem; }
  .why-choose-grid { grid-template-columns: 1fr; gap: 32px; }
  .why-choose-features { grid-template-columns: 1fr; }
  .hero-content h1 { font-size: clamp(1.6rem, 5vw, 2rem); }
  .hero-badge { margin-bottom: 16px; }
  .search-form { flex-direction: column; }
  .feed-view .main-content, .post-filter-wrap { grid-template-columns: 1fr; }
  .blog-content-area:has(.main-sidebar) { grid-template-columns: 1fr; }
  .sidebar-container { width: 100%; }
  .post-single { padding: 80px 16px 36px; }
  .footer-brand p { max-width: 100%; }
}
@media (max-width: 480px) {
  .about-stats { grid-template-columns: repeat(2, 1fr); }
  .process-grid { grid-template-columns: 1fr; }
  .post-share { justify-content: center; flex-wrap: wrap; }
  .popular-post-img { width: 56px; height: 56px; }
  .post-card-body h3 { font-size: 1rem; }
  .post-card-body { padding: 14px; }
  .post-card-meta { font-size: 12px; gap: 10px; }
  .service-card { padding: 28px 20px; }
  .lead-magnet-card { padding: 28px 20px; }
  .case-study-card { padding: 24px; }
  .hero-content h1 { font-size: clamp(1.4rem, 6vw, 1.7rem); }
  .hero-buttons .btn { width: 100%; text-align: center; }
  .hero-results { gap: 8px; }
  .hero-result-num { font-size: 1.15rem; }
  .hero-result-label { font-size: 10px; }
  .client-logos { gap: 20px; }
  .client-logo { font-size: 12px; }
  .section { padding: 28px 0; }
  .featured-posts { padding: 0 0 28px; }
  .post-single { padding: 72px 12px 28px; }
  .footer-grid, .footer-widgets { grid-template-columns: 1fr; }
}

/* --- Breadcrumb --- */
#breadcrumb { display: flex; align-items: center; gap: 8px; font-size: 13px; color: var(--text-lighter); margin-bottom: 16px; flex-wrap: wrap; }
#breadcrumb a { color: var(--text-lighter); text-decoration: none; }
#breadcrumb a:hover { color: var(--primary); }
#breadcrumb .delimiter { color: var(--text-lighter); font-size: 10px; }
#breadcrumb .current { color: var(--text); font-weight: 500; }

/* --- Blog Listing Grid --- */
.grid-posts { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: var(--gap-lg); }
.post-filter, .blog-post { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-md); overflow: hidden; transition: all 0.4s cubic-bezier(0.4,0,0.2,1); }
.post-filter:hover, .blog-post:hover { transform: translateY(-6px); box-shadow: var(--shadow-xl); border-color: var(--primary); }
.post-filter-inner { position: relative; display: block; aspect-ratio: 16/9; overflow: hidden; }
.post-filter-inner img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.6s ease; }
.blog-post:hover .post-filter-inner img { transform: scale(1.05); }
.post-filter-link { display: block; width: 100%; height: 100%; }
.piki-hero-flow { padding: 20px 24px; }
.post-tag { display: inline-block; background: var(--primary); color: #fff; padding: 3px 12px; border-radius: var(--radius-full); font-size: 11px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 10px; }
.piki-hero-flow .entry-title { font-size: 1rem; line-height: 1.4; }
.piki-hero-flow .entry-title a { color: var(--text); text-decoration: none; }
.piki-hero-flow .entry-title a:hover { color: var(--primary); }
.post-snippet { color: var(--text-light); font-size: 13px; line-height: 1.6; margin-top: 8px; }
.cat-badge { position: absolute; top: 12px; left: 12px; background: var(--primary); color: #fff; padding: 4px 12px; border-radius: 20px; font-size: 11px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.5px; }
.cat-badge a { color: #fff; text-decoration: none; }
.cat-badge a:hover { color: #fff; opacity: 0.85; }

/* --- Post Meta & Byline --- */
.all-flex { display: flex; align-items: center; justify-content: space-between; margin-bottom: 24px; padding-bottom: 20px; border-bottom: 1px solid var(--border); }
.post-inner-data { display: flex; align-items: center; gap: 12px; }
.post-inner-user .author-image { width: 40px; height: 40px; border-radius: var(--radius-full); overflow: hidden; }
.post-inner-user .author-image img { width: 100%; height: 100%; object-fit: cover; }
.post-inner-username .post-author-times { font-size: 14px; font-weight: 600; color: var(--text); }
.post-inner-username .post-author-times i { margin: 0 6px; color: var(--text-lighter); }
.post-times { font-size: 13px; color: var(--text-lighter); margin-top: 2px; }
.post-inner-comments { display: flex; align-items: center; gap: 12px; }
.comment-bubble { font-size: 13px; color: var(--text-lighter); display: flex; align-items: center; gap: 4px; }
.share-top { width: 36px; height: 36px; display: flex; align-items: center; justify-content: center; border-radius: var(--radius-full); background: var(--bg-alt); color: var(--text-light); cursor: pointer; font-size: 14px; transition: all var(--transition-fast); }
.share-top:hover { background: var(--primary); color: #fff; transform: translateY(-2px); }

/* --- Post Labels --- */
.label-container { display: flex; align-items: flex-start; gap: 8px; margin-top: 32px; padding-top: 24px; border-top: 1px solid var(--border); flex-wrap: wrap; }
.label-container span { font-size: 14px; font-weight: 600; color: var(--text); white-space: nowrap; }
.label-head { display: flex; flex-wrap: wrap; gap: 6px; }
.label-link { padding: 4px 14px; background: var(--bg-alt); border-radius: var(--radius-full); font-size: 12px; color: var(--text-light); font-weight: 500; text-decoration: none; transition: all var(--transition-fast); border: 1px solid transparent; }
.label-link:hover { background: var(--primary); color: #fff; border-color: var(--primary); }

/* --- Share Buttons --- */
.feed-share { margin-top: 24px; }
.oixvV-share { display: flex; align-items: center; gap: 8px; }
.oixvV-share li a { display: inline-flex; align-items: center; gap: 6px; padding: 8px 16px; border-radius: var(--radius-sm); font-size: 12px; font-weight: 600; text-decoration: none; transition: all var(--transition-fast); }

/* --- Author Box --- */
.oixvV-author { display: flex; align-items: flex-start; gap: 28px; padding: 36px; margin-top: 32px; background: var(--bg-alt); border: 1px solid var(--border); border-radius: var(--radius-md); }
.oixvV-author:hover { border-color: var(--primary); box-shadow: var(--shadow); }
.avatar-container { flex-shrink: 0; }
.avatar-container img { width: 88px; height: 88px; border-radius: var(--radius-full); object-fit: cover; border: 3px solid var(--primary); box-shadow: 0 4px 12px rgba(var(--primary-rgb),0.2); }
.author-description { flex: 1; }
.author-name { font-size: 1.1rem; margin-bottom: 4px; }
.author-name a { color: var(--text); text-decoration: none; }
.author-name a:hover { color: var(--primary); }
.author-expertise { font-size: 13px; color: var(--primary); font-weight: 600; margin-bottom: 8px; display: flex; align-items: center; gap: 6px; }
.author-expertise i { color: #f59e0b; }
.author-description > p { font-size: 14px; color: var(--text-light); line-height: 1.7; margin-bottom: 16px; }
.author-social { display: flex; gap: 8px; margin-bottom: 16px; }
.author-social a { width: 36px; height: 36px; display: flex; align-items: center; justify-content: center; background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-full); color: var(--text-light); font-size: 14px; text-decoration: none; transition: all var(--transition-fast); }
.author-social a:hover { background: var(--primary); border-color: var(--primary); color: #fff; transform: translateY(-2px); }
.author-cta { margin-top: 8px; }

@media (max-width: 480px) {
  .oixvV-author { flex-direction: column; align-items: center; text-align: center; padding: 24px; }
  .author-social { justify-content: center; }
}

/* --- Related Posts (container + heading hide together when empty/failed) --- */
.related-runs { margin-top: 40px; }
.related-runs:has(.Super-related:empty) { display: none; }
.related-runs .widget-title { display: flex; align-items: center; justify-content: space-between; padding: 0 0 20px; border-bottom: 1px solid var(--border); margin-bottom: 20px; }
.related-runs .widget-title h3 { font-size: 1.1rem; }
.related-runs .widget-title h3::before { display: none; }
.Super-related { display: grid; grid-template-columns: repeat(3, 1fr); gap: var(--gap); }
.related-post-item { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-md); overflow: hidden; transition: all 0.4s cubic-bezier(0.4,0,0.2,1); }
.related-post-item:hover { transform: translateY(-4px); box-shadow: var(--shadow-lg); border-color: var(--primary); }
.related-post-link { display: block; text-decoration: none; color: inherit; }
.related-post-img { width: 100%; aspect-ratio: 16/9; object-fit: cover; }
.related-post-title { font-family: var(--font-heading); font-size: 0.95rem; font-weight: 700; padding: 16px 16px 4px; color: var(--text); line-height: 1.4; }
.related-post-link:hover .related-post-title { color: var(--primary); }
.related-post-date { display: block; padding: 0 16px 16px; font-size: 12px; color: var(--text-lighter); }
.related-post-date i { margin-right: 4px; }

@media (max-width: 768px) {
  .Super-related { grid-template-columns: 1fr; }
}
@media (max-width: 480px) {
  .Super-related { grid-template-columns: 1fr; }
}

/* --- Lead Magnets Section --- */
.lead-magnets-section { background: var(--bg-alt); }
.lead-magnets-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: var(--gap-lg); }
.lead-magnet-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius-md); padding: 36px 28px; text-align: center; transition: all 0.4s cubic-bezier(0.4,0,0.2,1); display: flex; flex-direction: column; }
.lead-magnet-card:hover { transform: translateY(-6px); box-shadow: var(--shadow-xl); border-color: var(--primary); }
.lead-magnet-icon { width: 64px; height: 64px; margin: 0 auto 24px; background: linear-gradient(135deg, rgba(var(--primary-rgb),0.1), rgba(var(--primary-rgb),0.04)); border-radius: var(--radius); display: flex; align-items: center; justify-content: center; font-size: 28px; color: var(--primary); transition: all 0.3s ease; }
.lead-magnet-card:hover .lead-magnet-icon { background: linear-gradient(135deg, var(--primary), var(--primary-dark)); color: #fff; transform: scale(1.1) rotate(-5deg); }
.lead-magnet-card h3 { font-size: 1.1rem; margin-bottom: 12px; }
.lead-magnet-card > p { color: var(--text-light); font-size: 14px; line-height: 1.7; margin-bottom: 24px; }
.lead-magnet-features { margin-bottom: 24px; text-align: left; }
.lead-magnet-features li { display: flex; align-items: center; gap: 8px; padding: 6px 0; font-size: 13px; color: var(--text); border-bottom: 1px solid var(--border-light); }
.lead-magnet-features li:last-child { border-bottom: none; }
.lead-magnet-features li i { color: var(--accent); font-size: 14px; }
.lead-magnet-card .btn { margin-top: auto; }

@media (max-width: 768px) {
  .lead-magnets-grid { grid-template-columns: 1fr; }
}

/* --- Post CTA Box --- */
.post-cta-box { margin-top: 40px; padding: 36px; background: linear-gradient(135deg, var(--secondary), #1a237e); border-radius: var(--radius-lg); text-align: center; color: #fff; position: relative; overflow: hidden; }
.post-cta-box::before { content: ''; position: absolute; inset: 0; background-image: radial-gradient(rgba(255,255,255,0.03) 1px, transparent 1px); background-size: 30px 30px; pointer-events: none; }
.post-cta-content { position: relative; z-index: 1; }
.post-cta-content h3 { color: #fff; font-size: 1.5rem; margin-bottom: 8px; }
.post-cta-content p { color: rgba(255,255,255,0.75); margin-bottom: 16px; }
.post-cta-buttons { display: flex; gap: 16px; justify-content: center; flex-wrap: wrap; }
.post-cta-buttons .btn-secondary { color: #fff; border-color: rgba(255,255,255,0.4); }
.post-cta-buttons .btn-secondary:hover { background: #fff; color: var(--primary); border-color: #fff; }

/* --- Blog Pager --- */
.blog-pager-ok { text-align: center; margin: 48px 0; }
.load-more { display: inline-flex; align-items: center; justify-content: center; padding: 14px 36px; background: var(--primary); color: #fff; border-radius: var(--radius); font-weight: 600; font-size: 15px; text-decoration: none; transition: all var(--transition); }
.load-more:hover { background: var(--primary-dark); color: #fff; transform: translateY(-2px); box-shadow: 0 4px 12px rgba(var(--primary-rgb),0.3); }

/* --- Layout Mode --- */
#layout #header-section { position: relative; }
#layout .sticky-cta-bar, #layout .whatsapp-fab, #layout .back-to-top { display: none; }
#layout .footer-widgets { display: block; }
#layout .footer-col { float: left; width: 23%; margin: 0 1%; }
#layout .admin-section { display: block; }
#layout #theme-settings { display: block; }
#layout #main-nav .PageList { display: block; }
#layout #main-nav a { display: inline; padding: 0; }

/* --- Lead Form Fields --- */
.lead-form-fields { display: flex; flex-direction: column; gap: 10px; margin-bottom: 16px; }
.lead-input { width: 100%; padding: 13px 16px; border: 1.5px solid var(--border); border-radius: 8px; font-size: 14px; color: var(--text); background: var(--bg); outline: none; transition: all 0.2s ease; font-family: inherit; box-sizing: border-box; }
.lead-input:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(var(--primary-rgb),0.1); }
.lead-input:hover { border-color: var(--text-lighter); }
.lead-input::placeholder { color: var(--text-lighter); }
select.lead-input { appearance: auto; cursor: pointer; }

/* --- Client Logos Section --- */
.client-logos-section { background: var(--bg); padding: 40px 0; }
.client-logos-inner { text-align: center; }
.client-logo-label { font-size: 13px; color: var(--text-lighter); text-transform: uppercase; letter-spacing: 1px; margin-bottom: 24px; }
.client-logos { display: flex; align-items: center; justify-content: center; gap: 40px; flex-wrap: wrap; }
.client-logo { display: flex; align-items: center; gap: 8px; font-size: 14px; font-weight: 600; color: var(--text-light); opacity: 0.65; transition: all var(--transition-fast); }
.client-logo:hover { opacity: 1; transform: translateY(-2px); }
.client-logo i { font-size: 20px; color: var(--primary); }

@media print {
  .sticky-cta-bar, .whatsapp-fab, .header, .footer, .sidebar, .search-overlay, .mobile-menu, .mobile-overlay { display: none !important; }
  body { background: #fff; color: #000; }
}

