b:if.script:
 /**/
(function() {
  var body = document.getElementById('postBody');
  if (!body) return;

  // Reading time
  var text = body.textContent || body.innerText || '';
  var words = text.trim().split(/\s+/).length;
  var min = Math.max(1, Math.round(words / 200));
  var rt = document.getElementById('readTime');
  if (rt) rt.textContent = min + ' minute read';

  // Table of Contents - container is hidden by default (CSS),
  // only revealed here if 2+ headings are actually found.
  var headings = body.querySelectorAll('h2, h3');
  if (headings.length < 2) { return; }
  var tc = document.getElementById('tocContainer');
  var toc = document.getElementById('tocList');
  if (!tc || !toc) return;
  var ul = document.createElement('ul');
  headings.forEach(function(h, i) {
    if (!h.id) h.id = 'toc-' + i;
    var li = document.createElement('li');
    if (h.tagName === 'H3') li.style.paddingLeft = '1.5rem';
    var a = document.createElement('a');
    a.href = '#' + h.id;
    a.textContent = h.textContent;
    a.addEventListener('click', function(e) {
      e.preventDefault();
      h.scrollIntoView({ behavior: 'smooth', block: 'start' });
      history.pushState(null, '', '#' + h.id);
    });
    li.appendChild(a);
    ul.appendChild(li);
  });
  toc.appendChild(ul);
  tc.classList.add('has-toc');
})();
/**/

b:includable.script:
var disqus_blogger_current_url = "";
  if (!disqus_blogger_current_url.length) { disqus_blogger_current_url = ""; }
  var disqus_blogger_homepage_url = "";
  var disqus_blogger_canonical_homepage_url = "";

body.script:
//
/* ===========================================
   RankrSEO Theme - Vanilla JavaScript
   All interactive features, no jQuery required
   =========================================== */

(function() {
  'use strict';

  // --- DOM Ready ---
  function safeInit() { try { init(); } catch(e) {} }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', safeInit);
  } else {
    safeInit();
  }

  function init() {
    try { initStickyHeader(); } catch(e) {}
    try { initMobileMenu(); } catch(e) {}
    try { initDesktopDropdown(); } catch(e) {}
    try { initSearchOverlay(); } catch(e) {}
    try { initDarkMode(); } catch(e) {}
    try { initCounterAnimation(); } catch(e) {}
    try { initLazyLoading(); } catch(e) {}
    try { initScrollAnimations(); } catch(e) {}
    try { initBackToTop(); } catch(e) {}
    try { initStickyCtaBar(); } catch(e) {}
    try { initLeadForms(); } catch(e) {}
    try { initFaqAccordion(); } catch(e) {}
    try { initRelatedPosts(); } catch(e) {}
    try { initCardReadTime(); } catch(e) {}
    try { fixUnknownAuthor(); } catch(e) {}
    // Fallback: show all animate-on-scroll if anything failed
    document.querySelectorAll('.animate-on-scroll:not(.animated)').forEach(function(el) {
      el.classList.add('animated');
    });
  }

  // --- Sticky Header ---
  function initStickyHeader() {
    var header = document.getElementById('header');
    if (!header) return;
    var lastScroll = 0;
    var ticking = false;

    window.addEventListener('scroll', function() {
      if (!ticking) {
        window.requestAnimationFrame(function() {
          var scrollY = window.pageYOffset || document.documentElement.scrollTop;
          if (scrollY > 50) {
            header.classList.add('header-scrolled');
          } else {
            header.classList.remove('header-scrolled');
          }
          lastScroll = scrollY;
          ticking = false;
        });
        ticking = true;
      }
    }, { passive: true });
  }

  // --- Mobile Menu ---
  function initMobileMenu() {
    var menuToggle = document.getElementById('menuToggle');
    var menuClose = document.getElementById('mobileMenuClose');
    var mobileMenu = document.getElementById('mobileMenu');
    var mobileOverlay = document.getElementById('mobileOverlay');

    if (!menuToggle || !mobileMenu || !mobileOverlay) return;

    function openMenu() {
      mobileMenu.classList.add('active');
      mobileOverlay.classList.add('active');
      document.body.style.overflow = 'hidden';
    }

    function closeMenu() {
      mobileMenu.classList.remove('active');
      mobileOverlay.classList.remove('active');
      document.body.style.overflow = '';
    }

    menuToggle.addEventListener('click', openMenu);
    if (menuClose) menuClose.addEventListener('click', closeMenu);
    mobileOverlay.addEventListener('click', closeMenu);

    // Close on escape key
    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape' && mobileMenu.classList.contains('active')) {
        closeMenu();
      }
    });
  }

  // --- Desktop Services Dropdown (keyboard accessible) ---
  function initDesktopDropdown() {
    var toggle = document.getElementById('servicesToggle');
    var dropdown = document.getElementById('servicesDropdown');
    if (!toggle || !dropdown) return;
    var listItem = toggle.closest('li');

    function closeDropdown() {
      if (listItem) listItem.classList.remove('dropdown-open');
      toggle.setAttribute('aria-expanded', 'false');
    }
    function openDropdown() {
      if (listItem) listItem.classList.add('dropdown-open');
      toggle.setAttribute('aria-expanded', 'true');
    }

    toggle.addEventListener('click', function(e) {
      e.stopPropagation();
      var isOpen = listItem && listItem.classList.contains('dropdown-open');
      if (isOpen) { closeDropdown(); } else { openDropdown(); }
    });

    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape') {
        closeDropdown();
      }
    });

    document.addEventListener('click', function(e) {
      if (listItem && !listItem.contains(e.target)) {
        closeDropdown();
      }
    });

    dropdown.addEventListener('focusout', function() {
      // Defer so the newly-focused element is available to check
      window.requestAnimationFrame(function() {
        if (listItem && !listItem.contains(document.activeElement)) {
          closeDropdown();
        }
      });
    });
  }

  // --- Mobile Dropdown Toggle (global for onclick attr) ---
  window.toggleMobileDropdown = function(el) {
    var submenu = el.nextElementSibling;
    if (submenu && submenu.classList.contains('dropdown-menu-mobile')) {
      submenu.classList.toggle('active');
      var icon = el.querySelector('.fa-chevron-down');
      if (icon) {
        icon.style.transform = submenu.classList.contains('active') ? 'rotate(180deg)' : '';
      }
    }
  };

  // --- Search Overlay ---
  function initSearchOverlay() {
    var searchToggle = document.getElementById('searchToggle');
    var searchClose = document.getElementById('searchClose');
    var searchOverlay = document.getElementById('searchOverlay');

    if (!searchToggle || !searchOverlay) return;

    function openSearch() {
      searchOverlay.classList.add('active');
      document.body.style.overflow = 'hidden';
      var input = searchOverlay.querySelector('input[type="search"]');
      if (input) setTimeout(function() { input.focus(); }, 100);
    }

    function closeSearch() {
      searchOverlay.classList.remove('active');
      document.body.style.overflow = '';
    }

    searchToggle.addEventListener('click', openSearch);
    if (searchClose) searchClose.addEventListener('click', closeSearch);
    searchOverlay.addEventListener('click', function(e) {
      if (e.target === searchOverlay) closeSearch();
    });

    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape' && searchOverlay.classList.contains('active')) {
        closeSearch();
      }
      // Ctrl+K to open search
      if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
        e.preventDefault();
        openSearch();
      }
    });
  }

  // --- Dark Mode ---
  function initDarkMode() {
    var toggle = document.getElementById('themeToggle');
    if (!toggle) return;

    // data-theme is already applied pre-paint by the inline head script.
    // Just sync the button's accessible state on load.
    function syncAria() {
      var isDark = document.documentElement.getAttribute('data-theme') === 'dark';
      toggle.setAttribute('aria-pressed', isDark ? 'true' : 'false');
      toggle.setAttribute('aria-label', isDark ? 'Switch to light mode' : 'Switch to dark mode');
    }
    syncAria();

    toggle.addEventListener('click', function() {
      var html = document.documentElement;
      var isDark = html.getAttribute('data-theme') === 'dark';
      if (isDark) {
        html.removeAttribute('data-theme');
        localStorage.setItem('rankrseo-theme', 'light');
      } else {
        html.setAttribute('data-theme', 'dark');
        localStorage.setItem('rankrseo-theme', 'dark');
      }
      syncAria();
    });
  }

  // --- Counter Animation ---
  function initCounterAnimation() {
    var counters = document.querySelectorAll('.counter');
    if (!counters.length) return;

    var animated = false;

    function animateCounters() {
      if (animated) return;
      animated = true;

      counters.forEach(function(counter) {
        var target = parseInt(counter.getAttribute('data-target'), 10);
        if (isNaN(target)) target = 0;
        var duration = 2000;
        var startTime = null;

        function step(timestamp) {
          if (!startTime) startTime = timestamp;
          var progress = Math.min((timestamp - startTime) / duration, 1);
          var eased = 1 - Math.pow(1 - progress, 3);
          var current = Math.floor(eased * target);
          counter.textContent = current;
          if (progress < 1) {
            window.requestAnimationFrame(step);
          } else {
            counter.textContent = target;
          }
        }

        window.requestAnimationFrame(step);
      });
    }

    // Use IntersectionObserver to trigger when visible
    if ('IntersectionObserver' in window) {
      var observer = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) {
          if (entry.isIntersecting) {
            animateCounters();
            observer.disconnect();
          }
        });
      }, { threshold: 0.3 });

      var statsSection = document.getElementById('stats');
      if (statsSection) {
        observer.observe(statsSection);
      } else {
        // Fallback: observe any counter
        counters.forEach(function(c) {
          observer.observe(c);
        });
      }
    } else {
      // Fallback: animate on scroll event
      function checkScroll() {
        var statsSection = document.getElementById('stats');
        if (statsSection) {
          var rect = statsSection.getBoundingClientRect();
          if (rect.top < window.innerHeight && rect.bottom > 0) {
            animateCounters();
            window.removeEventListener('scroll', checkScroll);
          }
        }
      }
      window.addEventListener('scroll', checkScroll, { passive: true });
      checkScroll();
    }
  }

  // --- Lazy Loading ---
  function initLazyLoading() {
    var lazyImages = document.querySelectorAll('img.lazy');
    if (!lazyImages.length) return;

    if ('IntersectionObserver' in window) {
      var imageObserver = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) {
          if (entry.isIntersecting) {
            var img = entry.target;
            if (img.dataset.src) {
              img.src = img.dataset.src;
              img.removeAttribute('data-src');
            }
            img.classList.add('loaded');
            imageObserver.unobserve(img);
          }
        });
      }, { rootMargin: '200px 0px' });

      lazyImages.forEach(function(img) {
        imageObserver.observe(img);
      });
    } else {
      // Fallback: load all immediately
      lazyImages.forEach(function(img) {
        if (img.dataset.src) {
          img.src = img.dataset.src;
          img.removeAttribute('data-src');
        }
        img.classList.add('loaded');
      });
    }
  }

  // --- Scroll Animations ---
  function initScrollAnimations() {
    var elements = document.querySelectorAll('.animate-on-scroll');
    if (!elements.length) return;

    if ('IntersectionObserver' in window) {
      var animObserver = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) {
          if (entry.isIntersecting) {
            entry.target.classList.add('animated');
            animObserver.unobserve(entry.target);
          }
        });
      }, { threshold: 0.15 });

      elements.forEach(function(el) {
        animObserver.observe(el);
      });
    } else {
      // Fallback: show all immediately
      elements.forEach(function(el) {
        el.classList.add('animated');
      });
    }
  }

  // --- Back to Top Visibility ---
  function initBackToTop() {
    var btn = document.getElementById('backToTop');
    if (!btn) return;

    var ticking = false;
    window.addEventListener('scroll', function() {
      if (!ticking) {
        window.requestAnimationFrame(function() {
          var scrollY = window.pageYOffset || document.documentElement.scrollTop;
          if (scrollY > 400) {
            btn.classList.add('visible');
          } else {
            btn.classList.remove('visible');
          }
          ticking = false;
        });
        ticking = true;
      }
    }, { passive: true });
  }

  // --- Sticky CTA Bar ---
  function initStickyCtaBar() {
    var bar = document.getElementById('stickyCtaBar');
    var closeBtn = document.getElementById('stickyCtaClose');
    if (!bar) return;

    var dismissed = false;
    try { dismissed = sessionStorage.getItem('rankrseo-cta-dismissed') === '1'; } catch(e) {}
    if (dismissed) return;

    var contactSection = document.getElementById('contact');
    var heroSection = document.getElementById('hero');
    var hiddenNearContact = false;

    if ('IntersectionObserver' in window && contactSection) {
      var observer = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) {
          hiddenNearContact = entry.isIntersecting;
          updateVisibility();
        });
      }, { threshold: 0.1 });
      observer.observe(contactSection);
    }

    function updateVisibility() {
      var scrollY = window.pageYOffset || document.documentElement.scrollTop;
      var pastHero = heroSection ? scrollY > heroSection.offsetHeight * 0.6 : scrollY > 500;
      if (pastHero && !hiddenNearContact) {
        bar.classList.add('visible');
      } else {
        bar.classList.remove('visible');
      }
    }

    var ticking = false;
    window.addEventListener('scroll', function() {
      if (!ticking) {
        window.requestAnimationFrame(function() {
          updateVisibility();
          ticking = false;
        });
        ticking = true;
      }
    }, { passive: true });

    if (closeBtn) {
      closeBtn.addEventListener('click', function() {
        bar.classList.remove('visible');
        try { sessionStorage.setItem('rankrseo-cta-dismissed', '1'); } catch(e) {}
      });
    }
  }

  // --- Related Posts ---
  window._relatedIdx = 0;
  function initRelatedPosts() {
    var containers = document.querySelectorAll('.Super-related');
    if (!containers.length) return;
    containers.forEach(function(container) {
      var tagDiv = container.querySelector('.related-tag');
      if (!tagDiv) return;
      var label = tagDiv.getAttribute('label') || 'recent';
      var idx = ++window._relatedIdx;
      var id = 'related-' + idx;
      container.id = id;
      window['renderRelated_' + idx] = function(json) {
        var c = document.getElementById(id);
        if (!c || !json.feed || !json.feed.entry) return;
        c.innerHTML = '';
        json.feed.entry.forEach(function(entry) {
          var title = entry.title.$t || '';
          var href = '#';
          if (entry.link) {
            for (var k = 0; k < entry.link.length; k++) {
              if (entry.link[k].rel === 'alternate') { href = entry.link[k].href; break; }
            }
          }
          var thumb = '';
          if (entry.media$thumbnail) {
            thumb = entry.media$thumbnail.url.replace('/s72-c/', '/w400-h225-c/');
          }
          var date = '';
          if (entry.published) {
            date = new Date(entry.published.$t).toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
          }
          var item = document.createElement('div');
          item.className = 'related-post-item';
          var html = '<a class="related-post-link" href="' + href + '">';
          if (thumb) html += '<img class="related-post-img" src="' + thumb + '" alt="" loading="lazy"/>';
          html += '<h4 class="related-post-title">' + title + '</h4>';
          if (date) html += '<span class="related-post-date"><i class="far fa-calendar"></i> ' + date + '</span>';
          html += '</a>';
          item.innerHTML = html;
          c.appendChild(item);
        });
      };
      // If the JSONP request fails entirely (network error, blocked, or the
      // endpoint is ever retired), the related-runs wrapper still collapses
      // cleanly because .related-runs:has(.Super-related:empty) hides it -
      // there is no longer a heading left dangling with nothing underneath.
      var script = document.createElement('script');
      script.src = '/feeds/posts/default/-/' + encodeURIComponent(label) + '?alt=json-in-script&callback=renderRelated_' + idx + '&max-results=3';
      document.body.appendChild(script);
    });
  }

  // --- Blog Card Reading Time ---
  function initCardReadTime() {
    var cards = document.querySelectorAll('.post-card');
    if (!cards.length) return;
    cards.forEach(function(card) {
      var snippet = card.querySelector('.snippet');
      var readEl = card.querySelector('.read-time-card');
      if (snippet && readEl) {
        var text = snippet.textContent.trim();
        var words = text ? text.split(/\s+/).length : 0;
        var min = Math.max(1, Math.round(words / 200));
        readEl.textContent = min + ' min read';
      }
    });
  }

  // --- FAQ Accordion (global for onclick attr) ---
  window.toggleFaq = function(btn) {
    var item = btn.closest('.faq-item');
    if (!item) return;
    var answer = item.querySelector('.faq-answer');
    if (!answer) return;
    var isActive = item.classList.contains('active');

    // Close all FAQ items
    var allItems = document.querySelectorAll('.faq-item');
    allItems.forEach(function(el) {
      el.classList.remove('active');
      var a = el.querySelector('.faq-answer');
      if (a) a.style.maxHeight = '0';
      var b = el.querySelector('.faq-question');
      if (b) b.setAttribute('aria-expanded', 'false');
    });

    // Open clicked one if it wasn't already open
    if (!isActive) {
      item.classList.add('active');
      answer.style.maxHeight = answer.scrollHeight + 'px';
      btn.setAttribute('aria-expanded', 'true');
    }
  };

})();

// --- Lead Capture (newsletter + lead magnets) ---
// Blogger themes have no backend of their own, so these route into the
// one real, working channel: the native Contact Form widget. We pre-fill
// its email (and message, if provided) and scroll it into view so the
// visitor just has to hit send. Copy throughout is written to match this
// behavior honestly - no card promises an automatic download or email
// that this flow doesn't actually deliver.
function initLeadForms() {
  var forms = document.querySelectorAll('[data-lead-form]');
  var ctaButtons = document.querySelectorAll('[data-lead-cta]');

  function routeToContactForm(email, message) {
    var contactEmail = document.querySelector('.contact-form-email');
    var contactMessage = document.querySelector('.contact-form-email-message');
    var contactSection = document.getElementById('contact');

    if (contactEmail && email) contactEmail.value = email;
    if (contactMessage && message) contactMessage.value = message;

    if (contactSection) {
      contactSection.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
    if (contactMessage) {
      window.setTimeout(function() { contactMessage.focus(); }, 500);
    } else if (contactEmail) {
      window.setTimeout(function() { contactEmail.focus(); }, 500);
    }
  }

  forms.forEach(function(form) {
    form.addEventListener('submit', function(e) {
      e.preventDefault();
      var emailInput = form.querySelector('.lead-email-input');
      var email = emailInput ? emailInput.value.trim() : '';
      var message = form.getAttribute('data-lead-message') || '';
      routeToContactForm(email, message);

      var btn = form.querySelector('button[type="submit"]');
      if (btn) {
        var original = btn.innerHTML;
        btn.innerHTML = '<i class="fas fa-check"></i> Almost there &#8212; confirm below';
        window.setTimeout(function() { btn.innerHTML = original; }, 3000);
      }
    });
  });

  ctaButtons.forEach(function(btn) {
    btn.addEventListener('click', function() {
      var message = btn.getAttribute('data-lead-message') || '';
      routeToContactForm('', message);
      var original = btn.innerHTML;
      btn.innerHTML = '<i class="fas fa-arrow-down"></i> Scroll down and hit Send';
      window.setTimeout(function() { btn.innerHTML = original; }, 3000);
    });
  });
}

function fixUnknownAuthor() {
  var blogName = 'RankrSEO';
  var els = document.querySelectorAll('.post-author, .author-name, [itemprop="name"]');
  Array.prototype.forEach.call(els, function(el) {
    if (el.textContent.trim() === 'Unknown') el.textContent = blogName;
  });
}
//
